import bisect
import re
from typing import Dict, List, Optional, Tuple, Union

class InventoryManager:
    def __init__(self):
        self.inventory: List[Tuple[str, Dict]] = []  # List of (SKU, product_data) tuples, sorted by SKU

    def _validate_sku(self, sku: str) -> bool:
        """Validate SKU format - assuming SKU is alphanumeric with optional hyphens"""
        if not sku or not isinstance(sku, str):
            return False
        # Example pattern: alphanumeric with optional hyphens, 5-20 chars
        return bool(re.match(r'^[A-Za-z0-9\-]{5,20}$', sku))

    def _binary_search(self, sku: str) -> Tuple[int, bool]:
        """
        Perform binary search to find the position where SKU should be inserted/found
        Returns: (position, exists_flag)
        """
        left, right = 0, len(self.inventory) - 1

        while left <= right:
            mid = (left + right) // 2
            current_sku = self.inventory[mid][0]

            if current_sku == sku:
                return mid, True
            elif current_sku < sku:
                left = mid + 1
            else:
                right = mid - 1

        return left, False  # Return insertion position and flag that SKU doesn't exist

    def add_product(self, sku: str, product_data: Dict) -> bool:
        """Add a product to the inventory with O(log n) complexity"""
        if not self._validate_sku(sku):
            raise ValueError(f"Invalid SKU format: {sku}")

        pos, exists = self._binary_search(sku)
        if exists:
            return False  # SKU already exists

        self.inventory.insert(pos, (sku, product_data))
        return True

    def find_product(self, sku: str) -> Optional[Dict]:
        """Find a product by SKU with O(log n) complexity"""
        if not self._validate_sku(sku):
            raise ValueError(f"Invalid SKU format: {sku}")

        pos, exists = self._binary_search(sku)
        if exists:
            return self.inventory[pos][1]
        return None  # SKU not found

    def update_product(self, sku: str, product_data: Dict) -> bool:
        """Update a product's data with O(log n) complexity"""
        if not self._validate_sku(sku):
            raise ValueError(f"Invalid SKU format: {sku}")

        pos, exists = self._binary_search(sku)
        if exists:
            self.inventory[pos] = (sku, product_data)
            return True
        return False  # SKU not found

    def delete_product(self, sku: str) -> bool:
        """Delete a product with O(log n) complexity"""
        if not self._validate_sku(sku):
            raise ValueError(f"Invalid SKU format: {sku}")

        pos, exists = self._binary_search(sku)
        if not exists:
            return False  # SKU not found

        self.inventory.pop(pos)
        return True

    def get_inventory_size(self) -> int:
        """Return the current size of the inventory"""
        return len(self.inventory)

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <string.h>

#define MAX_SEATS 100
#define MAX_NAME_LENGTH 50

typedef struct {
    int seatNumber;
    char customerName[MAX_NAME_LENGTH];
    bool isBooked;
} Seat;

typedef struct Node {
    Seat seat;
    struct Node* next;
} Node;

typedef struct {
    Node* front;
    Node* rear;
    int size;
} Queue;

// Function prototypes
Queue* createQueue();
bool isEmpty(Queue* queue);
bool isFull(Queue* queue);
void enqueue(Queue* queue, Seat seat);
Seat dequeue(Queue* queue);
void initializeTheater(Queue* availableSeats, Seat allSeats[], int totalSeats);
bool bookTicket(Queue* availableSeats, Seat allSeats[], char* customerName);
bool cancelTicket(Queue* availableSeats, Seat allSeats[], int seatNumber);
void displayAvailableSeats(Queue* availableSeats);
void displayAllSeats(Seat allSeats[], int totalSeats);

int main() {
    Queue* availableSeats = createQueue();
    Seat allSeats[MAX_SEATS];
    int totalSeats = 50; // Can be changed based on theater capacity
    int choice, seatNumber;
    char customerName[MAX_NAME_LENGTH];

    initializeTheater(availableSeats, allSeats, totalSeats);

    while (1) {
        printf("\n=== Movie Theater Ticket Booking System ===\n");
        printf("1. Book a ticket\n");
        printf("2. Cancel a ticket\n");
        printf("3. Display available seats\n");
        printf("4. Display all seats\n");
        printf("5. Exit\n");
        printf("Enter your choice: ");
        scanf("%d", &choice);

        switch (choice) {
            case 1:
                printf("Enter customer name: ");
                scanf("%s", customerName);
                if (bookTicket(availableSeats, allSeats, customerName)) {
                    printf("Ticket booked successfully!\n");
                } else {
                    printf("Sorry, no seats available!\n");
                }
                break;

            case 2:
                printf("Enter seat number to cancel: ");
                scanf("%d", &seatNumber);
                if (cancelTicket(availableSeats, allSeats, seatNumber)) {
                    printf("Ticket cancelled successfully!\n");
                } else {
                    printf("Seat %d is not booked or does not exist!\n", seatNumber);
                }
                break;

            case 3:
                displayAvailableSeats(availableSeats);
                break;

            case 4:
                displayAllSeats(allSeats, totalSeats);
                break;

            case 5:
                printf("Thank you for using the Movie Theater Ticket Booking System!\n");
                exit(0);

            default:
                printf("Invalid choice! Please try again.\n");
        }
    }

    return 0;
}

Queue* createQueue() {
    Queue* queue = (Queue*)malloc(sizeof(Queue));
    if (queue != NULL) {
        queue->front = queue->rear = NULL;
        queue->size = 0;
    }
    return queue;
}

bool isEmpty(Queue* queue) {
    return (queue->size == 0);
}

bool isFull(Queue* queue) {
    return (queue->size == MAX_SEATS);
}

void enqueue(Queue* queue, Seat seat) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    if (newNode == NULL) {
        printf("Memory allocation failed!\n");
        return;
    }

    newNode->seat = seat;
    newNode->next = NULL;

    if (isEmpty(queue)) {
        queue->front = queue->rear = newNode;
    } else {
        queue->rear->next = newNode;
        queue->rear = newNode;
    }

    queue->size++;
}

Seat dequeue(Queue* queue) {
    Seat emptySeat = {-1, "", false};

    if (isEmpty(queue)) {
        return emptySeat;
    }

    Node* temp = queue->front;
    Seat seat = temp->seat;

    queue->front = queue->front->next;
    queue->size--;

    if (queue->front == NULL) {
        queue->rear = NULL;
    }

    free(temp);
    return seat;
}

void initializeTheater(Queue* availableSeats, Seat allSeats[], int totalSeats) {
    for (int i = 0; i < totalSeats; i++) {
        allSeats[i].seatNumber = i + 1;
        strcpy(allSeats[i].customerName, "");
        allSeats[i].isBooked = false;

        enqueue(availableSeats, allSeats[i]);
    }
}

bool bookTicket(Queue* availableSeats, Seat allSeats[], char* customerName) {
    if (isEmpty(availableSeats)) {
        return false;
    }

    Seat seat = dequeue(availableSeats);
    int seatIndex = seat.seatNumber - 1;

    strcpy(allSeats[seatIndex].customerName, customerName);
    allSeats[seatIndex].isBooked = true;

    return true;
}

bool cancelTicket(Queue* availableSeats, Seat allSeats[], int seatNumber) {
    if (seatNumber < 1 || seatNumber > MAX_SEATS) {
        return false;
    }

    int seatIndex = seatNumber - 1;

    if (!allSeats[seatIndex].isBooked) {
        return false;
    }

    strcpy(allSeats[seatIndex].customerName, "");
    allSeats[seatIndex].isBooked = false;

    enqueue(availableSeats, allSeats[seatIndex]);

    return true;
}

void displayAvailableSeats(Queue* availableSeats) {
    if (isEmpty(availableSeats)) {
        printf("No seats available!\n");
        return;
    }

    Queue* tempQueue = createQueue();
    Seat seat;

    printf("Available seats: ");
    while (!isEmpty(availableSeats)) {
        seat = dequeue(availableSeats);
        printf("%d ", seat.seatNumber);
        enqueue(tempQueue, seat);
    }
    printf("\n");

    // Restore the original queue
    while (!isEmpty(tempQueue)) {
        seat = dequeue(tempQueue);
        enqueue(availableSeats, seat);
    }

    free(tempQueue);
}

void displayAllSeats(Seat allSeats[], int totalSeats) {
    printf("\n=== Seat Status ===\n");
    printf("Seat No. | Status | Customer\n");
    printf("--------------------------\n");

    for (int i = 0; i < totalSeats; i++) {
        printf("   %2d   | %s | %s\n", 
               allSeats[i].seatNumber, 
               allSeats[i].isBooked ? "Booked" : "Available",
               allSeats[i].isBooked ? allSeats[i].customerName : "-");
    }
}

use std::error::Error;
use std::fmt;
use rand::Rng;

#[derive(Debug)]
pub enum ShuffleError {
    EmptyArray,
    UnsupportedType,
}

impl fmt::Display for ShuffleError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            ShuffleError::EmptyArray => write!(f, "Cannot shuffle an empty array"),
            ShuffleError::UnsupportedType => write!(f, "Unsupported data type for shuffling"),
        }
    }
}

impl Error for ShuffleError {}

pub fn shuffle<T: Clone>(array: &[T]) -> Result<Vec<T>, ShuffleError> {
    if array.is_empty() {
        return Err(ShuffleError::EmptyArray);
    }

    let mut rng = rand::thread_rng();
    let mut result = array.to_vec();

    // Fisher-Yates (Knuth) shuffle algorithm with O(n) complexity
    for i in (1..result.len()).rev() {
        let j = rng.gen_range(0..=i);
        result.swap(i, j);
    }

    Ok(result)
}

fn main() {
    // Example usage
    let int_array = [1, 2, 3, 4, 5];
    match shuffle(&int_array) {
        Ok(shuffled) => println!("Shuffled integers: {:?}", shuffled),
        Err(e) => eprintln!("Error: {}", e),
    }

    let str_array = ["apple", "banana", "cherry", "date"];
    match shuffle(&str_array) {
        Ok(shuffled) => println!("Shuffled strings: {:?}", shuffled),
        Err(e) => eprintln!("Error: {}", e),
    }

    let empty_array: [i32; 0] = [];
    match shuffle(&empty_array) {
        Ok(shuffled) => println!("Shuffled empty array: {:?}", shuffled),
        Err(e) => eprintln!("Error: {}", e),
    }
}

