class LogEntry {
public:
    std::chrono::system_clock::time_point timestamp;
    std::string event;

    LogEntry(const std::chrono::system_clock::time_point& ts, const std::string& evt)
        : timestamp(ts), event(evt) {}

    friend std::ostream& operator<<(std::ostream& os, const LogEntry& entry) {
        time_t tt = std::chrono::system_clock::to_time_t(entry.timestamp);
        os << std::ctime(&tt) << ": " << entry.event;
        return os;
    }
};

class LogManager {
private:
    std::multimap<std::chrono::system_clock::time_point, std::string> logs;
    std::string dbFilename;

public:
    LogManager(const std::string& filename = "logs.db") : dbFilename(filename) {
        loadFromFile();
    }

    ~LogManager() {
        saveToFile();
    }

    void addLog(const std::chrono::system_clock::time_point& timestamp, const std::string& event) {
        logs.insert({timestamp, event});
    }

    std::vector<LogEntry> queryRange(
        const std::chrono::system_clock::time_point& start,
        const std::chrono::system_clock::time_point& end) {

        std::vector<LogEntry> results;

        // Binary search equivalent using lower_bound for O(log n) complexity
        auto itStart = logs.lower_bound(start);
        auto itEnd = logs.upper_bound(end);

        for (auto it = itStart; it != itEnd; ++it) {
            results.push_back(LogEntry(it->first, it->second));
        }

        return results;
    }

    void saveToFile() {
        std::ofstream file(dbFilename, std::ios::binary);
        if (!file) {
            std::cerr << "Error: Could not open file for writing: " << dbFilename << std::endl;
            return;
        }

        size_t size = logs.size();
        file.write(reinterpret_cast<const char*>(&size), sizeof(size));

        for (const auto& log : logs) {
            auto timestamp = log.first.time_since_epoch().count();
            file.write(reinterpret_cast<const char*>(&timestamp), sizeof(timestamp));

            size_t eventLength = log.second.length();
            file.write(reinterpret_cast<const char*>(&eventLength), sizeof(eventLength));
            file.write(log.second.c_str(), eventLength);
        }
    }

    void loadFromFile() {
        std::ifstream file(dbFilename, std::ios::binary);
        if (!file) {
            std::cerr << "Info: No existing log database found or could not open: " << dbFilename << std::endl;
            return;
        }

        logs.clear();

        size_t size;
        file.read(reinterpret_cast<char*>(&size), sizeof(size));

        for (size_t i = 0; i < size; i++) {
            typename std::chrono::system_clock::duration::rep timestamp;
            file.read(reinterpret_cast<char*>(&timestamp), sizeof(timestamp));

            std::chrono::system_clock::time_point tp{std::chrono::system_clock::duration{timestamp}};

            size_t eventLength;
            file.read(reinterpret_cast<char*>(&eventLength), sizeof(eventLength));

            std::string event(eventLength, ' ');
            file.read(&event[0], eventLength);

            logs.insert({tp, event});
        }
    }

    void clearLogs() {
        logs.clear();
    }

    size_t size() const {
        return logs.size();
    }
};

int main() {
    LogManager logManager("portal_logs.db");

    // Example usage
    auto now = std::chrono::system_clock::now();
    auto yesterday = now - std::chrono::hours(24);
    auto twoDaysAgo = now - std::chrono::hours(48);

    // Add some logs
    logManager.addLog(twoDaysAgo, "User login: user123");
    logManager.addLog(twoDaysAgo + std::chrono::minutes(5), "Page view: home");
    logManager.addLog(yesterday, "User login: admin");
    logManager.addLog(yesterday + std::chrono::minutes(10), "Configuration change");
    logManager.addLog(now, "System backup");

    // Query logs from yesterday to now
    std::cout << "Logs from yesterday to now:\n";
    auto results = logManager.queryRange(yesterday, now);
    for (const auto& entry : results) {
        std::cout << entry;
    }

    // Save logs to file (also happens in destructor)
    logManager.saveToFile();

    return 0;
}

import java.util.*;

class Node {
    int id;
    List<Node> subordinates;

    public Node(int id) {
        this.id = id;
        this.subordinates = new ArrayList<>();
    }

    public void addSubordinate(Node subordinate) {
        subordinates.add(subordinate);
    }
}

public class OrganizationLCA {
    private Node[] nodes;
    private int[] depth;
    private int[][] ancestors;
    private int maxLog;

    public OrganizationLCA(int size) {
        nodes = new Node[size];
        for (int i = 0; i < size; i++) {
            nodes[i] = new Node(i);
        }

        depth = new int[size];
        maxLog = (int) (Math.log(size) / Math.log(2)) + 1;
        ancestors = new int[size][maxLog];

        for (int i = 0; i < size; i++) {
            Arrays.fill(ancestors[i], -1);
        }
    }

    public void addRelationship(int managerId, int subordinateId) {
        nodes[managerId].addSubordinate(nodes[subordinateId]);
    }

    public void preprocessHierarchy(int rootId) {
        dfs(nodes[rootId], null, 0);
        computeAncestors();
    }

    private void dfs(Node current, Node parent, int currentDepth) {
        depth[current.id] = currentDepth;

        if (parent != null) {
            ancestors[current.id][0] = parent.id;
        }

        for (Node subordinate : current.subordinates) {
            dfs(subordinate, current, currentDepth + 1);
        }
    }

    private void computeAncestors() {
        for (int j = 1; j < maxLog; j++) {
            for (int i = 0; i < nodes.length; i++) {
                if (ancestors[i][j-1] != -1) {
                    ancestors[i][j] = ancestors[ancestors[i][j-1]][j-1];
                }
            }
        }
    }

    public int findLCA(int nodeAId, int nodeBId) {
        if (depth[nodeAId] < depth[nodeBId]) {
            int temp = nodeAId;
            nodeAId = nodeBId;
            nodeBId = temp;
        }

        // Bring nodes to the same depth
        int depthDiff = depth[nodeAId] - depth[nodeBId];
        for (int i = 0; i < maxLog; i++) {
            if (((depthDiff >> i) & 1) == 1) {
                nodeAId = ancestors[nodeAId][i];
            }
        }

        if (nodeAId == nodeBId) {
            return nodeAId;
        }

        // Find LCA
        for (int i = maxLog - 1; i >= 0; i--) {
            if (ancestors[nodeAId][i] != ancestors[nodeBId][i]) {
                nodeAId = ancestors[nodeAId][i];
                nodeBId = ancestors[nodeBId][i];
            }
        }

        return ancestors[nodeAId][0];
    }

    public void updateHierarchy(int managerId, int subordinateId) {
        // Remove old relationship
        for (Node node : nodes) {
            node.subordinates.removeIf(sub -> sub.id == subordinateId);
        }

        // Add new relationship
        nodes[managerId].addSubordinate(nodes[subordinateId]);

        // Recompute hierarchy information
        int rootId = findRoot();
        preprocessHierarchy(rootId);
    }

    private int findRoot() {
        boolean[] hasParent = new boolean[nodes.length];
        for (Node node : nodes) {
            for (Node subordinate : node.subordinates) {
                hasParent[subordinate.id] = true;
            }
        }

        for (int i = 0; i < nodes.length; i++) {
            if (!hasParent[i]) {
                return i;
            }
        }

        return 0; // Default to first node if no clear root
    }

    public static void main(String[] args) {
        // Example usage
        int size = 10;
        OrganizationLCA org = new OrganizationLCA(size);

        // Build initial hierarchy
        org.addRelationship(0, 1);
        org.addRelationship(0, 2);
        org.addRelationship(1, 3);
        org.addRelationship(1, 4);
        org.addRelationship(2, 5);
        org.addRelationship(2, 6);
        org.addRelationship(4, 7);
        org.addRelationship(4, 8);
        org.addRelationship(5, 9);

        org.preprocessHierarchy(0);

        // Find LCA examples
        int lca1 = org.findLCA(7, 8);
        int lca2 = org.findLCA(3, 7);
        int lca3 = org.findLCA(7, 9);

        // Update hierarchy
        org.updateHierarchy(3, 9); // Move employee 9 under employee 3

        // Find LCA after update
        int newLca = org.findLCA(7, 9);
    }
}

