// Document representation
class Document {
private:
    std::string id;
    std::string title;
    std::string content;
    std::map<std::string, std::string> metadata;

public:
    Document(const std::string& id, const std::string& title, const std::string& content)
        : id(id), title(title), content(content) {}

    const std::string& getId() const { return id; }
    const std::string& getTitle() const { return title; }
    const std::string& getContent() const { return content; }

    void addMetadata(const std::string& key, const std::string& value) {
        metadata[key] = value;
    }

    std::string getMetadata(const std::string& key) const {
        auto it = metadata.find(key);
        return it != metadata.end() ? it->second : "";
    }
};

// Inverted index with optimized search for O(n log n) complexity
class InvertedIndex {
private:
    std::unordered_map<std::string, std::vector<std::string>> index; // Term -> document IDs
    std::unordered_map<std::string, std::unique_ptr<Document>> documents; // Document ID -> Document

    // Tokenize content into words - O(n) where n is the content length
    std::vector<std::string> tokenize(const std::string& content) {
        std::vector<std::string> tokens;
        std::istringstream iss(content);
        std::string token;

        while (iss >> token) {
            // Convert to lowercase and remove non-alphanumeric characters - O(token length)
            token.erase(std::remove_if(token.begin(), token.end(), 
                [](char c) { return !std::isalnum(c); }), token.end());

            if (!token.empty()) {
                std::transform(token.begin(), token.end(), token.begin(), 
                    [](unsigned char c) { return std::tolower(c); });
                tokens.push_back(token);
            }
        }

        return tokens;
    }

public:
    // Add document to the index - O(n) where n is document size
    void addDocument(std::unique_ptr<Document> document) {
        if (!document) {
            return;
        }

        std::string docId = document->getId();
        std::vector<std::string> tokens = tokenize(document->getContent());

        // Build index for this document - O(n) where n is the number of tokens
        for (const auto& token : tokens) {
            index[token].push_back(docId);
        }

        documents[docId] = std::move(document);
    }

    // Search for documents containing the keyword - O(result size)
    std::vector<const Document*> search(const std::string& keyword) const {
        std::vector<const Document*> results;
        std::string lowerKeyword = keyword;
        std::transform(lowerKeyword.begin(), lowerKeyword.end(), lowerKeyword.begin(), 
            [](unsigned char c) { return std::tolower(c); });

        auto it = index.find(lowerKeyword);
        if (it != index.end()) {
            // Reserve space to avoid reallocations - O(1)
            results.reserve(it->second.size());

            // Build result list - O(result size)
            for (const auto& docId : it->second) {
                auto docIt = documents.find(docId);
                if (docIt != documents.end()) {
                    results.push_back(docIt->second.get());
                }
            }
        }

        return results;
    }

    // Search for documents containing multiple keywords 
    // Overall complexity: O(n log n) where n is the total number of document references across all keywords
    std::vector<const Document*> searchMultiple(const std::vector<std::string>& keywords) const {
        if (keywords.empty()) {
            return {};
        }

        // Find the keyword with the smallest posting list to minimize initial set
        size_t minSize = std::numeric_limits<size_t>::max();
        std::string bestKeyword;

        // O(k) where k is the number of keywords
        for (const auto& keyword : keywords) {
            std::string lowerKeyword = keyword;
            std::transform(lowerKeyword.begin(), lowerKeyword.end(), lowerKeyword.begin(), 
                [](unsigned char c) { return std::tolower(c); });

            auto it = index.find(lowerKeyword);
            if (it != index.end() && it->second.size() < minSize) {
                minSize = it->second.size();
                bestKeyword = lowerKeyword;
            }
        }

        if (bestKeyword.empty()) {
            return {}; // No matches for any keyword
        }

        // Start with the documents matching the least frequent term
        std::set<std::string> candidateDocIds;
        auto it = index.find(bestKeyword);
        if (it != index.end()) {
            // O(m log m) where m is the size of the smallest posting list
            candidateDocIds.insert(it->second.begin(), it->second.end());
        }

        // Filter candidates by other keywords
        for (const auto& keyword : keywords) {
            if (keyword == bestKeyword) continue;

            std::string lowerKeyword = keyword;
            std::transform(lowerKeyword.begin(), lowerKeyword.end(), lowerKeyword.begin(), 
                [](unsigned char c) { return std::tolower(c); });

            it = index.find(lowerKeyword);
            if (it == index.end()) {
                return {}; // No documents match this keyword
            }

            // Convert the current keyword's document list to a set for O(log n) lookups
            std::set<std::string> currentTermDocs(it->second.begin(), it->second.end());

            // Perform set intersection - O(n log n) where n is the size of candidateDocIds
            std::set<std::string> intersection;
            for (const auto& docId : candidateDocIds) {
                if (currentTermDocs.find(docId) != currentTermDocs.end()) {
                    intersection.insert(docId);
                }
            }

            // Update candidates with intersection results
            candidateDocIds = std::move(intersection);

            if (candidateDocIds.empty()) {
                return {}; // No documents match all keywords so far
            }
        }

        // Convert final candidate set to Document pointers - O(result size)
        std::vector<const Document*> results;
        results.reserve(candidateDocIds.size());

        for (const auto& docId : candidateDocIds) {
            auto docIt = documents.find(docId);
            if (docIt != documents.end()) {
                results.push_back(docIt->second.get());
            }
        }

        return results;
    }

    // Get size of the index
    size_t size() const {
        return documents.size();
    }
};

