// Document collection manager
class DocumentCollection {
private:
    InvertedIndex index;

public:
    bool loadDocument(const std::string& path) {
        try {
            fs::path pathObj(path);
            if (!fs::exists(pathObj)) {
                std::cerr << "File does not exist: " << path << std::endl;
                return false;
            }

            std::string extension = pathObj.extension().string();
            auto loader = DocumentLoader::createLoader(extension);
            auto document = loader->loadDocument(path);

            if (document) {
                index.addDocument(std::move(document));
                return true;
            }

            return false;
        } catch (const std::exception& e) {
            std::cerr << "Error loading document: " << e.what() << std::endl;
            return false;
        }
    }

    bool loadDirectory(const std::string& dirPath) {
        try {
            if (!fs::exists(dirPath) || !fs::is_directory(dirPath)) {
                std::cerr << "Invalid directory path: " << dirPath << std::endl;
                return false;
            }

            bool success = true;
            for (const auto& entry : fs::directory_iterator(dirPath)) {
                if (fs::is_regular_file(entry.path())) {
                    success &= loadDocument(entry.path().string());
                }
            }

            return success;
        } catch (const std::exception& e) {
            std::cerr << "Error loading directory: " << e.what() << std::endl;
            return false;
        }
    }

    std::vector<const Document*> search(const std::string& keyword) const {
        return index.search(keyword);
    }

    std::vector<const Document*> searchMultiple(const std::vector<std::string>& keywords) const {
        return index.searchMultiple(keywords);
    }

    size_t size() const {
        return index.size();
    }
};

