    if (argc < 2) {
        std::cout << "Usage: " << argv[0] << " <directory_path>" << std::endl;
        return 1;
    }

    std::string dirPath = argv[1];
    std::cout << "Loading documents from: " << dirPath << std::endl;

    if (!collection.loadDirectory(dirPath)) {
        std::cerr << "Failed to load some documents" << std::endl;
    }

    std::cout << "Loaded " << collection.size() << " documents successfully." << std::endl;
    std::cout << "Enter search keywords (comma-separated): ";

