        if (input.empty()) {
            break;
        }

        std::vector<std::string> keywords;
        std::istringstream iss(input);
        std::string keyword;
        while (std::getline(iss, keyword, ',')) {
            // Trim whitespace
            keyword.erase(0, keyword.find_first_not_of(" \t\n\r\f\v"));
            keyword.erase(keyword.find_last_not_of(" \t\n\r\f\v") + 1);

            if (!keyword.empty()) {
                keywords.push_back(keyword);
            }
        }

        auto results = collection.searchMultiple(keywords);

        std::cout << "Found " << results.size() << " matching documents:" << std::endl;
