        let a = BigUint::from(witnesses[i]);

        // Skip if a >= n
        if &a >= n {
            continue;
        }

        // Compute a^d mod n - O(log d) operation with binary exponentiation
        let mut x = a.modpow(&d, n);

        if x == BigUint::one() || x == n_minus_one {
