#include <iostream>
#include <vector>
#include <string>
#include <memory>
#include <unordered_map>
#include <algorithm>
#include <stdexcept>
#include <fstream>

class SuffixTree {
private:
    struct Node {
        std::unordered_map<char, std::unique_ptr<Node>> children;
        int start, end;
        Node* suffix_link;

        Node(int start = -1, int end = -1) 
            : start(start), end(end), suffix_link(nullptr) {}
    };

    std::string text;
    std::unique_ptr<Node> root;
    std::vector<Node*> leaf_nodes;

    // Ukkonen's algorithm for suffix tree construction in O(n) time
    void build() {
        root = std::make_unique<Node>();
        Node* active_node = root.get();
        int active_edge = -1;
        int active_length = 0;

        int remaining = 0;

        for (int i = 0; i < text.length(); ++i) {
            remaining++;
            Node* last_created_node = nullptr;

            while (remaining > 0) {
                if (active_length == 0) {
                    active_edge = i;
                }

                if (active_node->children.find(text[active_edge]) == active_node->children.end()) {
                    // Create a new leaf node
                    active_node->children[text[active_edge]] = std::make_unique<Node>(i, text.length());
                    leaf_nodes.push_back(active_node->children[text[active_edge]].get());

                    // Set suffix link if needed
                    if (last_created_node != nullptr) {
                        last_created_node->suffix_link = active_node;
                        last_created_node = nullptr;
                    }
                } else {
                    // Existing edge, walk down
                    Node* next = active_node->children[text[active_edge]].get();
                    int edge_length = next->end - next->start;

                    if (active_length >= edge_length) {
                        // Walk past current edge
                        active_edge += edge_length;
                        active_length -= edge_length;
                        active_node = next;
                        continue;
                    }

                    // Check if character matches
                    if (text[next->start + active_length] == text[i]) {
                        active_length++;
                        // Set suffix link if needed
                        if (last_created_node != nullptr) {
                            last_created_node->suffix_link = active_node;
                            last_created_node = nullptr;
                        }
                        break;
                    }

                    // Split the edge
                    int split_point = next->start + active_length;
                    auto split_node = std::make_unique<Node>(next->start, split_point);
                    active_node->children[text[active_edge]] = std::move(split_node);
                    Node* split_node_ptr = active_node->children[text[active_edge]].get();

                    split_node_ptr->children[text[split_point]] = std::make_unique<Node>(split_point, next->end);
                    Node* original_node = split_node_ptr->children[text[split_point]].get();
                    original_node->children = std::move(next->children);

                    // Create a new leaf
                    split_node_ptr->children[text[i]] = std::make_unique<Node>(i, text.length());
                    leaf_nodes.push_back(split_node_ptr->children[text[i]].get());

                    // Handle suffix links
                    if (last_created_node != nullptr) {
                        last_created_node->suffix_link = split_node_ptr;
                    }
                    last_created_node = split_node_ptr;
                }

                remaining--;

                // Follow suffix link or go to root
                if (active_node == root.get() && active_length > 0) {
                    active_length--;
                    active_edge = i - remaining + 1;
                } else {
                    active_node = (active_node->suffix_link != nullptr) ? active_node->suffix_link : root.get();
                }
            }
        }
    }

    // Traverse down the tree to find a pattern - O(m) time
    Node* traverseToNode(const std::string& pattern) {
        Node* current = root.get();
        int pattern_index = 0;

        while (pattern_index < pattern.length()) {
            char current_char = pattern[pattern_index];
            if (current->children.find(current_char) == current->children.end()) {
                return nullptr; // Pattern not found
            }

            Node* child = current->children[current_char].get();
            int edge_length = child->end - child->start;

            // Check if the edge matches the pattern
            for (int i = 0; i < edge_length && pattern_index < pattern.length(); ++i) {
                if (pattern[pattern_index] != text[child->start + i]) {
                    return nullptr; // Mismatch
                }
                pattern_index++;
            }

            current = child;
        }

        return current;
    }

    // Collect all leaf positions from a subtree - O(z) time
    void collectLeafPositions(Node* node, std::vector<int>& positions) {
        if (node->children.empty()) {
            // This is a leaf node, its start position gives the suffix start
            positions.push_back(node->start - (text.length() - node->end));
            return;
        }

        // Recursively search all children
        for (auto& pair : node->children) {
            collectLeafPositions(pair.second.get(), positions);
        }
    }

public:
    SuffixTree(const std::string& text) : text(text) {
        if (text.empty()) {
            throw std::invalid_argument("Cannot build suffix tree with empty text");
        }
        build();
    }

    // Find all occurrences of pattern in O(m + z) time
    std::vector<int> findSubstring(const std::string& pattern) {
        if (pattern.empty()) {
            throw std::invalid_argument("Search pattern cannot be empty");
        }

        std::vector<int> positions;
        Node* node = traverseToNode(pattern);

        if (node != nullptr) {
            collectLeafPositions(node, positions);
        }

        return positions;
    }
};

class TextProcessor {
private:
    SuffixTree suffixTree;
    std::string document;

public:
    TextProcessor(const std::string& filepath) : document("") {
        try {
            loadDocument(filepath);
            suffixTree = SuffixTree(document);
        } catch (const std::exception& e) {
            std::cerr << "Error initializing TextProcessor: " << e.what() << std::endl;
            throw;
        }
    }

    void loadDocument(const std::string& filepath) {
        std::ifstream file(filepath);
        if (!file) {
            throw std::runtime_error("Failed to open file: " + filepath);
        }

        std::string content((std::istreambuf_iterator<char>(file)),
                             std::istreambuf_iterator<char>());
        document = content;

        if (document.empty()) {
            throw std::runtime_error("Document is empty");
        }
    }

    std::vector<int> findAllOccurrences(const std::string& pattern) {
        try {
            if (pattern.empty()) {
                throw std::invalid_argument("Search pattern cannot be empty");
            }
            return suffixTree.findSubstring(pattern);
        } catch (const std::exception& e) {
            std::cerr << "Error finding occurrences: " << e.what() << std::endl;
            return {};
        }
    }

    void displayOccurrences(const std::string& pattern) {
        try {
            std::vector<int> positions = findAllOccurrences(pattern);

            if (positions.empty()) {
                std::cout << "Pattern \"" << pattern << "\" not found in document." << std::endl;
                return;
            }

            std::cout << "Found " << positions.size() << " occurrences of \"" << pattern << "\":" << std::endl;
            for (int pos : positions) {
                int contextStart = std::max(0, pos - 20);
                int contextEnd = std::min(static_cast<int>(document.size()), pos + static_cast<int>(pattern.size()) + 20);

                std::cout << "Position " << pos << ": ..." 
                          << document.substr(contextStart, pos - contextStart) 
                          << "[" << document.substr(pos, pattern.size()) << "]"
                          << document.substr(pos + pattern.size(), contextEnd - (pos + pattern.size()))
                          << "..." << std::endl;
            }
        } catch (const std::exception& e) {
            std::cerr << "Error displaying occurrences: " << e.what() << std::endl;
        }
    }
};

