            std::cout << "\nEnter a substring to search (or 'exit' to quit): ";
            std::getline(std::cin, query);

            if (query == "exit") {
                break;
            }

            if (query.empty()) {
                std::cout << "Error: Empty query. Please enter a valid substring." << std::endl;
                continue;
