class BTreeNode {
  constructor(leaf = true, order = 5) {
    this.leaf = leaf;
    this.keys = [];
    this.children = [];
    this.order = order;
  }

  isFull() {
    return this.keys.length === 2 * this.order - 1;
  }
}

