class BTree {
  constructor(order = 5) {
    this.root = new BTreeNode(true, order);
    this.order = order;
  }

  search(key, compareFunction) {
    return this._search(this.root, key, compareFunction);
  }

  _search(node, key, compareFunction) {
    let i = 0;
    while (i < node.keys.length && compareFunction(key, node.keys[i]) > 0) {
      i++;
    }

    if (i < node.keys.length && compareFunction(key, node.keys[i]) === 0) {
      return node.keys[i];
    }

    if (node.leaf) {
      return null;
    }

    return this._search(node.children[i], key, compareFunction);
  }

  insert(key) {
    let root = this.root;

    if (root.isFull()) {
      let newRoot = new BTreeNode(false, this.order);
      newRoot.children.push(root);
      this.root = newRoot;
      this._splitChild(newRoot, 0);
      this._insertNonFull(newRoot, key);
    } else {
      this._insertNonFull(root, key);
    }
  }

  _insertNonFull(node, key) {
    let i = node.keys.length - 1;

    const compareFunction = (a, b) => {
      return a.title.localeCompare(b.title);
    };

    if (node.leaf) {
      while (i >= 0 && compareFunction(key, node.keys[i]) < 0) {
        node.keys[i + 1] = node.keys[i];
        i--;
      }

      // Check for duplicate
      if (i >= 0 && key.title === node.keys[i].title) {
        return; // Skip duplicate insertion
      }

      node.keys[i + 1] = key;
    } else {
      while (i >= 0 && compareFunction(key, node.keys[i]) < 0) {
        i--;
      }

      i++;

      if (node.children[i].isFull()) {
        this._splitChild(node, i);

        if (compareFunction(key, node.keys[i]) > 0) {
          i++;
        }
      }

      this._insertNonFull(node.children[i], key);
    }
  }

  _splitChild(parentNode, index) {
    const order = this.order;
    const childNode = parentNode.children[index];
    const newNode = new BTreeNode(childNode.leaf, order);

    parentNode.keys.splice(index, 0, childNode.keys[order - 1]);

    for (let j = 0; j < order - 1; j++) {
      newNode.keys.push(childNode.keys[j + order]);
    }

    childNode.keys.length = order - 1;

    if (!childNode.leaf) {
      for (let j = 0; j < order; j++) {
        newNode.children.push(childNode.children[j + order]);
      }

      childNode.children.length = order;
    }

    parentNode.children.splice(index + 1, 0, newNode);
  }

  delete(key) {
    if (this.root.keys.length === 0) {
      return;
    }

    const compareFunction = (a, b) => {
      return a.title.localeCompare(b.title);
    };

    this._deleteKey(this.root, key, compareFunction);

    if (this.root.keys.length === 0 && !this.root.leaf) {
      this.root = this.root.children[0];
    }
  }

  _deleteKey(node, key, compareFunction) {
    let index = this._findKey(node, key, compareFunction);

    if (index < node.keys.length && compareFunction(node.keys[index], key) === 0) {
      if (node.leaf) {
        node.keys.splice(index, 1);
      } else {
        this._deleteFromNonLeaf(node, index);
      }
    } else {
      if (node.leaf) {
        return;
      }

      const lastChild = index === node.children.length;

      if (node.children[index].keys.length < this.order) {
        this._fill(node, index);
      }

      if (lastChild && index > node.children.length - 1) {
        this._deleteKey(node.children[index - 1], key, compareFunction);
      } else {
        this._deleteKey(node.children[index], key, compareFunction);
      }
    }
  }

  _deleteFromNonLeaf(node, index) {
    const key = node.keys[index];

    if (node.children[index].keys.length >= this.order) {
      const predecessor = this._getPredecessor(node, index);
      node.keys[index] = predecessor;
      this._deleteKey(node.children[index], predecessor, (a, b) => a.title.localeCompare(b.title));
    } else if (node.children[index + 1].keys.length >= this.order) {
      const successor = this._getSuccessor(node, index);
      node.keys[index] = successor;
      this._deleteKey(node.children[index + 1], successor, (a, b) => a.title.localeCompare(b.title));
    } else {
      this._merge(node, index);
      this._deleteKey(node.children[index], key, (a, b) => a.title.localeCompare(b.title));
    }
  }

  _getPredecessor(node, index) {
    let current = node.children[index];

    while (!current.leaf) {
      current = current.children[current.keys.length];
    }

    return current.keys[current.keys.length - 1];
  }

  _getSuccessor(node, index) {
    let current = node.children[index + 1];

    while (!current.leaf) {
      current = current.children[0];
    }

    return current.keys[0];
  }

  _fill(node, index) {
    if (index !== 0 && node.children[index - 1].keys.length >= this.order) {
      this._borrowFromPrev(node, index);
    } else if (index !== node.keys.length && node.children[index + 1].keys.length >= this.order) {
      this._borrowFromNext(node, index);
    } else {
      if (index !== node.keys.length) {
        this._merge(node, index);
      } else {
        this._merge(node, index - 1);
      }
    }
  }

  _borrowFromPrev(node, index) {
    const child = node.children[index];
    const sibling = node.children[index - 1];

    for (let i = child.keys.length - 1; i >= 0; i--) {
      child.keys[i + 1] = child.keys[i];
    }

    if (!child.leaf) {
      for (let i = child.children.length - 1; i >= 0; i--) {
        child.children[i + 1] = child.children[i];
      }
    }

    child.keys[0] = node.keys[index - 1];

    if (!child.leaf) {
      child.children[0] = sibling.children[sibling.children.length - 1];
    }

    node.keys[index - 1] = sibling.keys[sibling.keys.length - 1];

    sibling.keys.pop();
    if (!sibling.leaf) {
      sibling.children.pop();
    }
  }

  _borrowFromNext(node, index) {
    const child = node.children[index];
    const sibling = node.children[index + 1];

    child.keys.push(node.keys[index]);

    if (!child.leaf) {
      child.children.push(sibling.children[0]);
    }

    node.keys[index] = sibling.keys[0];

    sibling.keys.shift();

    if (!sibling.leaf) {
      sibling.children.shift();
    }
  }

  _merge(node, index) {
    const child = node.children[index];
    const sibling = node.children[index + 1];

    child.keys.push(node.keys[index]);

    for (let i = 0; i < sibling.keys.length; i++) {
      child.keys.push(sibling.keys[i]);
    }

    if (!child.leaf) {
      for (let i = 0; i < sibling.children.length; i++) {
        child.children.push(sibling.children[i]);
      }
    }

    node.keys.splice(index, 1);
    node.children.splice(index + 1, 1);
  }

  _findKey(node, key, compareFunction) {
    let index = 0;

    while (index < node.keys.length && compareFunction(node.keys[index], key) < 0) {
      index++;
    }

    return index;
  }
}

class BookCatalog {
  constructor() {
    this.btree = new BTree(3);
    this.authorIndex = new Map();
  }

  addBook(title, author) {
    if (!this.validateInput(title, author)) {
      return false;
    }

    const book = new Book(title, author);

    // Check if book already exists
    if (this.searchByTitle(title)) {
      console.log(`Book with title "${title}" already exists`);
      return false;
    }

    this.btree.insert(book);

    // Update author index
    if (!this.authorIndex.has(author)) {
      this.authorIndex.set(author, []);
    }
    this.authorIndex.get(author).push(book);

    return true;
  }

  validateInput(title, author) {
    if (!title || typeof title !== 'string' || title.trim() === '') {
      console.log('Invalid title');
      return false;
    }

    if (!author || typeof author !== 'string' || author.trim() === '') {
      console.log('Invalid author');
      return false;
    }

    return true;
  }

  searchByTitle(title) {
    const dummyBook = new Book(title, '');
    return this.btree.search(dummyBook, (a, b) => a.title.localeCompare(b.title));
  }

  searchByAuthor(author) {
    return this.authorIndex.has(author) ? this.authorIndex.get(author) : [];
  }

  deleteBook(title) {
    const book = this.searchByTitle(title);

    if (!book) {
      console.log(`Book with title "${title}" not found`);
      return false;
    }

    // Remove from author index
    const author = book.author;
    const authorBooks = this.authorIndex.get(author);
    const index = authorBooks.findIndex(b => b.title === title);

    if (index !== -1) {
      authorBooks.splice(index, 1);

      if (authorBooks.length === 0) {
        this.authorIndex.delete(author);
      }
    }

    // Remove from B-Tree
    const dummyBook = new Book(title, '');
    this.btree.delete(dummyBook);

    return true;
  }

  loadFromJSON(jsonData) {
    try {
      const data = typeof jsonData === 'string' ? JSON.parse(jsonData) : jsonData;

      if (!Array.isArray(data)) {
        console.log('Invalid JSON data: expected an array');
        return false;
      }

      let successCount = 0;

      for (const item of data) {
        if (item.title && item.author) {
          if (this.addBook(item.title, item.author)) {
            successCount++;
          }
        } else {
          console.log('Invalid book entry:', item);
        }
      }

      console.log(`Successfully loaded ${successCount} out of ${data.length} books`);
      return successCount > 0;
    } catch (error) {
      console.error('Error loading JSON data:', error);
      return false;
    }
  }
}

