class UserActivityTracker {
private:
    struct UserActivity {
        std::string userId;
        size_t activityCount;

        UserActivity(const std::string& id, size_t count) : userId(id), activityCount(count) {}

        bool operator<(const UserActivity& other) const {
            return activityCount > other.activityCount; // For descending order
        }
    };

    std::unordered_map<std::string, size_t> userActivities;
    std::mutex dataMutex;
    std::atomic<bool> running;
    std::condition_variable dataCV;
    std::thread updateThread;
    std::queue<std::string> updateQueue;
    std::mutex queueMutex;

public:
    UserActivityTracker() : running(true) {
        // Start the update thread
        updateThread = std::thread(&UserActivityTracker::processUpdates, this);
    }

    ~UserActivityTracker() {
        // Signal the update thread to stop
        running = false;
        dataCV.notify_one();

        // Wait for the thread to finish
        if (updateThread.joinable()) {
            updateThread.join();
        }
    }

    void loadFromFile(const std::string& filename) {
        std::ifstream file(filename);
        if (!file) {
            throw std::runtime_error("Failed to open file: " + filename);
        }

        std::string line;
        std::string userId;
        size_t lineCount = 0;

        try {
            while (std::getline(file, line)) {
                lineCount++;
                // Simple parsing: assume each line contains a user ID
                // In a real system, you would parse more complex log formats
                if (!line.empty()) {
                    size_t delimiter = line.find(',');
                    if (delimiter != std::string::npos) {
                        userId = line.substr(0, delimiter);
                    } else {
                        userId = line;
                    }

                    std::lock_guard<std::mutex> lock(dataMutex);
                    userActivities[userId]++;
                }
            }
        } catch (const std::exception& e) {
            std::cerr << "Error processing line " << lineCount << ": " << e.what() << std::endl;
            // Continue processing despite errors
        }

        file.close();
    }

    void addActivity(const std::string& userId) {
        // Queue the update for processing by the update thread
        std::lock_guard<std::mutex> lock(queueMutex);
        updateQueue.push(userId);
        dataCV.notify_one();
    }

    void processUpdates() {
        while (running) {
            std::unique_lock<std::mutex> lock(queueMutex);
            dataCV.wait(lock, [this] { return !updateQueue.empty() || !running; });

            if (!running && updateQueue.empty()) {
                break;
            }

            std::vector<std::string> batch;
            while (!updateQueue.empty()) {
                batch.push_back(updateQueue.front());
                updateQueue.pop();
            }
            lock.unlock();

            // Process the batch
            std::lock_guard<std::mutex> dataLock(dataMutex);
            for (const auto& userId : batch) {
                userActivities[userId]++;
            }
        }
    }

    std::vector<std::pair<std::string, size_t>> getTopK(size_t k) {
        std::vector<UserActivity> activities;

        {
            std::lock_guard<std::mutex> lock(dataMutex);
            activities.reserve(userActivities.size());
            for (const auto& pair : userActivities) {
                activities.emplace_back(pair.first, pair.second);
            }
        }

        // Using partial_sort which is O(n log k)
        if (k < activities.size()) {
            std::partial_sort(activities.begin(), activities.begin() + k, activities.end());
            activities.resize(k);
        } else {
            std::sort(activities.begin(), activities.end());
        }

        std::vector<std::pair<std::string, size_t>> result;
        result.reserve(activities.size());
        for (const auto& activity : activities) {
            result.emplace_back(activity.userId, activity.activityCount);
        }

        return result;
    }

    size_t getTotalUsers() const {
        std::lock_guard<std::mutex> lock(dataMutex);
        return userActivities.size();
    }
};

