use std::collections::{HashMap, BTreeMap};
use std::error::Error;
use std::fmt;
use std::io;

#[derive(Default)]
struct TrieNode {
    is_end_of_word: bool,
    children: HashMap<char, TrieNode>,
    // Store suggestions in a sorted structure for O(log n) operations
    top_suggestions: BTreeMap<(i32, String), ()>,
}

struct Trie {
    root: TrieNode,
    max_suggestions: usize,
}

#[derive(Debug)]
enum TrieError {
    EmptyQuery,
    InvalidCharacter(char),
}

impl fmt::Display for TrieError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            TrieError::EmptyQuery => write!(f, "Empty query is not allowed"),
            TrieError::InvalidCharacter(c) => write!(f, "Invalid character in query: {}", c),
        }
    }
}

impl Error for TrieError {}

impl Trie {
    fn new() -> Self {
        Trie {
            root: TrieNode::default(),
            max_suggestions: 10,
        }
    }

    fn insert(&mut self, query: &str) -> Result<(), TrieError> {
        if query.is_empty() {
            return Err(TrieError::EmptyQuery);
        }

        // Validate characters
        for c in query.chars() {
            if !c.is_alphanumeric() && !c.is_whitespace() {
                return Err(TrieError::InvalidCharacter(c));
            }
        }

        // Insert the query
        let mut current = &mut self.root;
        let mut prefix = String::new();

        // Track nodes to update
        let mut path = Vec::new();
        path.push(&mut self.root as *mut TrieNode);

        for c in query.chars() {
            prefix.push(c);
            current = current.children.entry(c).or_default();
            path.push(current as *mut TrieNode);
        }

        // Mark as end of word and record the query
        current.is_end_of_word = true;

        // Update frequency for this query in all nodes along the path
        for node_ptr in path {
            // Safety: These pointers are valid as we just created them
            unsafe {
                let node = &mut *node_ptr;

                // Remove any existing entry for this query to update frequency
                let key_to_remove = node.top_suggestions
                    .keys()
                    .find(|(_, s)| s == query)
                    .map(|k| k.clone());

                if let Some(key) = key_to_remove {
                    node.top_suggestions.remove(&key);
                }

                // Calculate new frequency (negative for reverse sorting)
                let new_freq = match key_to_remove {
                    Some((freq, _)) => freq - 1, // Increment by making more negative
                    None => -1,                  // First occurrence
                };

                // Insert with updated frequency
                node.top_suggestions.insert((new_freq, query.to_string()), ());

                // Trim to max size - O(log n) operation
                while node.top_suggestions.len() > self.max_suggestions {
                    // Remove the least frequent query (highest negative value)
                    if let Some(last_key) = node.top_suggestions.keys().next_back().cloned() {
                        node.top_suggestions.remove(&last_key);
                    }
                }
            }
        }

        Ok(())
    }

    // O(log n) autocomplete using BTreeMap
    fn autocomplete(&self, prefix: &str) -> Result<Vec<String>, TrieError> {
        if prefix.is_empty() {
            return Err(TrieError::EmptyQuery);
        }

        // Validate characters
        for c in prefix.chars() {
            if !c.is_alphanumeric() && !c.is_whitespace() {
                return Err(TrieError::InvalidCharacter(c));
            }
        }

        // Find the node corresponding to the prefix
        let mut current = &self.root;
        for c in prefix.chars() {
            match current.children.get(&c) {
                Some(next) => current = next,
                None => return Ok(Vec::new()), // Prefix not found
            }
        }

        // Extract suggestions in order - O(log n) operations
        let mut results = Vec::new();

        for (_, query) in current.top_suggestions.keys() {
            if query.starts_with(prefix) {
                results.push(query.clone());
            }
        }

        Ok(results)
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let mut trie = Trie::new();

    println!("Search Query Autocomplete System (O(log n) Complexity)");
    println!("Commands: ADD <query>, SEARCH <prefix>, EXIT");

    loop {
        let mut input = String::new();
        println!("\nEnter command:");

        io::stdin().read_line(&mut input)?;
        let input = input.trim();

        if input.eq_ignore_ascii_case("EXIT") {
            break;
        }

        let parts: Vec<&str> = input.splitn(2, ' ').collect();

        if parts.len() < 2 {
            println!("Invalid command format. Use: ADD <query> or SEARCH <prefix>");
            continue;
        }

        let command = parts[0];
        let query = parts[1];

        match command.to_uppercase().as_str() {
            "ADD" => {
                match trie.insert(query) {
                    Ok(_) => println!("Added query: {}", query),
                    Err(e) => println!("Error adding query: {}", e),
                }
            },
            "SEARCH" => {
                match trie.autocomplete(query) {
                    Ok(suggestions) => {
                        if suggestions.is_empty() {
                            println!("No suggestions found for: {}", query);
                        } else {
                            println!("Suggestions for '{}': ", query);
                            for (i, suggestion) in suggestions.iter().enumerate() {
                                println!("  {}. {}", i + 1, suggestion);
                            }
                        }
                    },
                    Err(e) => println!("Error searching: {}", e),
                }
            },
            _ => println!("Unknown command: {}. Use ADD, SEARCH or EXIT", command),
        }
    }

    println!("Exiting...");
    Ok(())
}

class SuffixTreeNode {
    constructor() {
        this.children = new Map();
        this.suffixLink = null;
        this.start = -1;
        this.end = null;
        this.suffixIndex = -1;
    }

    get edgeLength() {
        return this.end === null ? Infinity : this.end - this.start;
    }
}

class ActivePoint {
    constructor() {
        this.node = null;
        this.edge = '';
        this.length = 0;
    }
}

class SuffixTree {
    constructor(text) {
        this.text = text;
        this.root = new SuffixTreeNode();
        this.activePoint = new ActivePoint();
        this.remainder = 0;
        this.currentEnd = -1;
        this.leafEnd = null;
        this.splitEnd = null;
        this.activePoint.node = this.root;
        this.buildTree();
    }

    buildTree() {
        if (!this.text || this.text.length === 0) return;

        // Ukkonen's algorithm for O(n) suffix tree construction
        for (let i = 0; i < this.text.length; i++) {
            this.extend(i);
        }

        // Mark suffix indices
        this.markSuffixIndices(this.root, 0);
    }

    extend(pos) {
        this.leafEnd = pos + 1;
        this.remainder++;
        let lastNewNode = null;

        while (this.remainder > 0) {
            if (this.activePoint.length === 0) {
                this.activePoint.edge = this.text[pos];
            }

            if (!this.activePoint.node.children.has(this.activePoint.edge)) {
                // Create a new leaf node
                const newNode = new SuffixTreeNode();
                newNode.start = pos - this.activePoint.length + 1;
                newNode.end = this.leafEnd;
                this.activePoint.node.children.set(this.activePoint.edge, newNode);

                // Set suffix link if needed
                if (lastNewNode !== null) {
                    lastNewNode.suffixLink = this.activePoint.node;
                    lastNewNode = null;
                }
            } else {
                // There's already an edge starting with the current character
                const nextNode = this.activePoint.node.children.get(this.activePoint.edge);
                const edgeLength = Math.min(nextNode.edgeLength, this.text.length - nextNode.start);

                // If active length is greater than the current edge length, move down
                if (this.activePoint.length >= edgeLength) {
                    this.activePoint.edge = this.text[pos];
                    this.activePoint.length -= edgeLength;
                    this.activePoint.node = nextNode;
                    continue;
                }

                // Check if the character at active point matches current character
                if (this.text[nextNode.start + this.activePoint.length] === this.text[pos]) {
                    this.activePoint.length++;

                    // Set suffix link if needed
                    if (lastNewNode !== null) {
                        lastNewNode.suffixLink = this.activePoint.node;
                        lastNewNode = null;
                    }

                    break;
                }

                // Need to split the edge
                const splitNode = new SuffixTreeNode();
                splitNode.start = nextNode.start;
                splitNode.end = nextNode.start + this.activePoint.length;
                this.activePoint.node.children.set(this.activePoint.edge, splitNode);

                // Create new leaf node
                const newLeaf = new SuffixTreeNode();
                newLeaf.start = pos;
                newLeaf.end = this.leafEnd;
                splitNode.children.set(this.text[pos], newLeaf);

                // Update original node
                nextNode.start += this.activePoint.length;
                splitNode.children.set(this.text[nextNode.start], nextNode);

                // Set suffix link
                if (lastNewNode !== null) {
                    lastNewNode.suffixLink = splitNode;
                }
                lastNewNode = splitNode;
            }

            this.remainder--;

            // Rule 1: If active node is root, reduce active length, change active edge
            if (this.activePoint.node === this.root && this.activePoint.length > 0) {
                this.activePoint.length--;
                this.activePoint.edge = this.text[pos - this.remainder + 1];
            } else if (this.activePoint.node !== this.root) {
                // Rule 3: Follow suffix link if available
                this.activePoint.node = this.activePoint.node.suffixLink || this.root;
            }
        }
    }

    markSuffixIndices(node, depth) {
        let isLeaf = true;

        for (const [char, child] of node.children.entries()) {
            isLeaf = false;
            this.markSuffixIndices(child, depth + (child.end - child.start));
        }

        if (isLeaf) {
            node.suffixIndex = this.text.length - depth;
        }
    }

    findLongestRepeatedSubstring() {
        if (!this.text || this.text.length === 0) {
            return "";
        }

        let maxLength = 0;
        let maxNode = null;
        const visited = new Set();

        const dfs = (node, depth) => {
            if (!node) return 0;

            let childVisits = 0;
            for (const [char, childNode] of node.children.entries()) {
                const edgeLength = childNode.end - childNode.start;
                const childVisit = dfs(childNode, depth + edgeLength);
                childVisits += childVisit;
            }

            // If this node is visited from at least two distinct paths and has greater depth
            if (childVisits >= 2 && depth > maxLength) {
                maxLength = depth;
                maxNode = node;
            }

            return childVisits > 0 ? childVisits : 1;
        };

        dfs(this.root, 0);

        if (maxLength === 0) return "";

        // Reconstruct the longest repeated substring
        let result = "";
        const reconstructPath = (node, depth, targetDepth) => {
            if (depth === targetDepth) return true;

            for (const [char, childNode] of node.children.entries()) {
                const edgeLength = childNode.end - childNode.start;
                const segment = this.text.substring(childNode.start, childNode.end);

                if (depth + edgeLength <= targetDepth) {
                    result += segment;
                    if (reconstructPath(childNode, depth + edgeLength, targetDepth)) {
                        return true;
                    }
                    result = result.substring(0, result.length - segment.length);
                } else {
                    const partialLength = targetDepth - depth;
                    result += this.text.substring(childNode.start, childNode.start + partialLength);
                    return true;
                }
            }

            return false;
        };

        reconstructPath(this.root, 0, maxLength);
        return result;
    }
}

