class Playlist {
    private Node head;
    private Node tail;
    private int size;

    public Playlist() {
        head = null;
        tail = null;
        size = 0;
    }

    public boolean isEmpty() {
        return size == 0;
    }

    public int size() {
        return size;
    }

    public boolean containsTitle(String title) {
        if (isEmpty()) {
            return false;
        }

        Node current = head;
        while (current != null) {
            if (current.song.getTitle().equalsIgnoreCase(title)) {
                return true;
            }
            current = current.next;
        }
        return false;
    }

    public void addSong(Song song) {
        if (containsTitle(song.getTitle())) {
            System.out.println("Error: A song with this title already exists in the playlist.");
            return;
        }

        Node newNode = new Node(song);

        if (isEmpty()) {
            head = newNode;
            tail = newNode;
        } else {
            tail.next = newNode;
            newNode.prev = tail;
            tail = newNode;
        }
        size++;
        System.out.println("Song '" + song.getTitle() + "' added successfully.");
    }

    public void removeSong(String title) {
        if (isEmpty()) {
            System.out.println("Error: Playlist is empty.");
            return;
        }

        Node current = head;

        // Search for the song
        while (current != null) {
            if (current.song.getTitle().equalsIgnoreCase(title)) {
                // Found the song to remove

                // If it's the only node
                if (size == 1) {
                    head = null;
                    tail = null;
                }
                // If it's the head
                else if (current == head) {
                    head = head.next;
                    head.prev = null;
                }
                // If it's the tail
                else if (current == tail) {
                    tail = tail.prev;
                    tail.next = null;
                }
                // If it's in the middle
                else {
                    current.prev.next = current.next;
                    current.next.prev = current.prev;
                }

                size--;
                System.out.println("Song '" + title + "' removed successfully.");
                return;
            }
            current = current.next;
        }

        System.out.println("Error: Song '" + title + "' not found in the playlist.");
