        Node songNode = null;
        Node current = head;
        int currentPos = 1;

        while (current != null) {
            if (current.song.getTitle().equalsIgnoreCase(title)) {
                songNode = current;
                break;
            }
            current = current.next;
            currentPos++;
        }

        if (songNode == null) {
            System.out.println("Error: Song '" + title + "' not found in the playlist.");
            return;
        }

        // If the song is already at the requested position
        if (currentPos == newPosition) {
            System.out.println("Song '" + title + "' is already at position " + newPosition + ".");
            return;
        }

        // Remove the song from its current position
        if (songNode == head) {
            head = head.next;
            if (head != null) {
                head.prev = null;
            } else {
                tail = null;
            }
        } else if (songNode == tail) {
            tail = tail.prev;
            tail.next = null;
        } else {
            songNode.prev.next = songNode.next;
            songNode.next.prev = songNode.prev;
        }

        // Insert the song at the new position
        current = head;
        currentPos = 1;

        // If inserting at the beginning
        if (newPosition == 1) {
            songNode.next = head;
            songNode.prev = null;
            if (head != null) {
                head.prev = songNode;
            } else {
                tail = songNode;
            }
            head = songNode;
        } 
        // If inserting at the end
        else if (newPosition == size) {
            songNode.next = null;
            songNode.prev = tail;
            tail.next = songNode;
            tail = songNode;
        } 
        // If inserting in the middle
        else {
            current = head;
            for (int i = 1; i < newPosition; i++) {
                current = current.next;
            }

            songNode.next = current;
            songNode.prev = current.prev;
            current.prev.next = songNode;
            current.prev = songNode;
        }

        System.out.println("Song '" + title + "' moved to position " + newPosition + ".");
    }

