    public static void main(String[] args) {
        try {
            // Read salaries from CSV file
            List<Integer> salaries = readSalariesFromCSV("salaries.csv");

            if (salaries.isEmpty()) {
                System.out.println("No valid salary data found.");
                return;
            }

            // Create copies for different gap sequences
            List<Integer> salaries1 = new ArrayList<>(salaries);
            List<Integer> salaries2 = new ArrayList<>(salaries);

            // Test with different gap sequences
            System.out.println("Testing different gap sequences for Shell sort...");

            long startTime = System.nanoTime();
            shellSortOriginal(salaries1);
            long endTime = System.nanoTime();
            System.out.println("Original Shell sequence: " + (endTime - startTime) / 1000000.0 + " ms");

            startTime = System.nanoTime();
            shellSortOptimized(salaries2);
            endTime = System.nanoTime();
            System.out.println("Optimized sequence: " + (endTime - startTime) / 1000000.0 + " ms");

            // Print first few sorted salaries
            System.out.println("\nFirst 10 sorted salaries:");
            for (int i = 0; i < Math.min(10, salaries1.size()); i++) {
                System.out.println(salaries1.get(i));
            }

        } catch (Exception e) {
            System.err.println("Error processing salaries: " + e.getMessage());
        }
    }

    // Read salaries from CSV file and validate
    private static List<Integer> readSalariesFromCSV(String filename) {
        List<Integer> salaries = new ArrayList<>();

        try (BufferedReader br = new BufferedReader(new FileReader(filename))) {
            String line;
            int lineNumber = 0;

            while ((line = br.readLine()) != null) {
                lineNumber++;
                try {
                    // Assuming CSV has salary in first column
                    String[] data = line.split(",");
                    int salary = Integer.parseInt(data[0].trim());

                    // Validate salary is positive
                    if (salary <= 0) {
                        System.err.println("Warning: Negative or zero salary at line " + lineNumber + ". Skipping.");
                        continue;
                    }

                    salaries.add(salary);
                } catch (NumberFormatException e) {
                    System.err.println("Warning: Invalid salary format at line " + lineNumber + ". Skipping.");
                } catch (ArrayIndexOutOfBoundsException e) {
                    System.err.println("Warning: Missing data at line " + lineNumber + ". Skipping.");
                }
            }

            System.out.println("Successfully loaded " + salaries.size() + " valid salaries.");

        } catch (FileNotFoundException e) {
            System.err.println("File not found: " + filename);
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
        }

        return salaries;
    }

    // Shell sort with original sequence (n/2, n/4, ..., 1)
    // This has worst-case O(n²) time complexity
    private static void shellSortOriginal(List<Integer> arr) {
        int n = arr.size();

        // Start with a big gap, then reduce the gap
        for (int gap = n/2; gap > 0; gap /= 2) {
            // Do a gapped insertion sort
            for (int i = gap; i < n; i++) {
                int temp = arr.get(i);
                int j;

                // Shift earlier gap-sorted elements up until the correct location for a[i] is found
                for (j = i; j >= gap && arr.get(j - gap) > temp; j -= gap) {
                    arr.set(j, arr.get(j - gap));
                }

                // Put temp (the original a[i]) in its correct location
                arr.set(j, temp);
            }
        }
    }

    // Shell sort with a sequence ensuring O(n²) time complexity
    private static void shellSortOptimized(List<Integer> arr) {
        int n = arr.size();

        // Using a simple arithmetic sequence (n/2, n/3, n/4, ..., 1)
        // This has a proven worst-case O(n²) time complexity
        for (int div = 2; div <= n; div++) {
            int gap = n / div;
            if (gap < 1) gap = 1;

            for (int i = gap; i < n; i++) {
                int temp = arr.get(i);
                int j = i;

                while (j >= gap && arr.get(j - gap) > temp) {
                    arr.set(j, arr.get(j - gap));
                    j -= gap;
                }

                arr.set(j, temp);
            }
        }
    }
}

