class TabHistory {
  constructor() {
    this.current = null;
    this.size = 0;
  }

  openTab(url, title) {
    const newTab = new TabNode(url, title);

    if (this.current !== null) {
      // Clear forward history
      if (this.current.next !== null) {
        this.current.next = null;
      }

      // Link the new tab
      newTab.prev = this.current;
      this.current.next = newTab;
    }

    this.current = newTab;
    this.size++;

    return newTab;
  }

  closeTab() {
    if (this.current === null) {
      throw new Error("No tabs to close");
    }

    const closed = this.current;

    if (this.current.prev !== null) {
      // Go back to previous tab
      this.current = this.current.prev;
      this.current.next = closed.next;

      if (closed.next !== null) {
        closed.next.prev = this.current;
      }
    } else if (this.current.next !== null) {
      // Go forward to next tab
      this.current = this.current.next;
      this.current.prev = null;
    } else {
      // This was the only tab
      this.current = null;
    }

    this.size--;
    return closed;
  }

  goBack() {
    if (this.current === null || this.current.prev === null) {
      throw new Error("No previous tab available");
    }

    this.current = this.current.prev;
    return this.current;
  }

  goForward() {
    if (this.current === null || this.current.next === null) {
      throw new Error("No forward tab available");
    }

    this.current = this.current.next;
    return this.current;
  }

  getCurrentTab() {
    if (this.current === null) {
      throw new Error("No tab is currently open");
    }

    return this.current;
  }

  canGoBack() {
    return this.current !== null && this.current.prev !== null;
  }

  canGoForward() {
    return this.current !== null && this.current.next !== null;
  }

  getSize() {
    return this.size;
  }
}

