bool readStudentRecords(const std::string& filename, std::vector<Student>& students) {
    std::ifstream file(filename);
    if (!file) {
        std::cerr << "Error: Could not open file " << filename << std::endl;
        return false;
    }

    students.clear();
    students.reserve(10000); // Reserve space for up to 10,000 records

    std::string line;
    while (std::getline(file, line) && students.size() < 10000) {
        size_t pos = line.find_last_of(" \t");
        if (pos != std::string::npos) {
            std::string name = line.substr(0, pos);
            std::string gpaStr = line.substr(pos + 1);

            try {
                double gpa = std::stod(gpaStr);
                students.push_back({name, gpa});
            } catch (const std::exception& e) {
                std::cerr << "Warning: Invalid GPA format in line: " << line << std::endl;
                // Continue processing other records
            }
        } else {
            std::cerr << "Warning: Invalid format in line: " << line << std::endl;
            // Continue processing other records
        }
    }

    file.close();
    return true;
}

void selectionSort(std::vector<Student>& students) {
    size_t n = students.size();

    for (size_t i = 0; i < n - 1; i++) {
        size_t max_idx = i;

        // Find the index of the maximum GPA in the unsorted part
        for (size_t j = i + 1; j < n; j++) {
            if (students[j].gpa > students[max_idx].gpa) {
                max_idx = j;
            }
        }

        // Swap the found maximum element with the first element
        if (max_idx != i) {
            Student temp = students[i];
            students[i] = students[max_idx];
            students[max_idx] = temp;
        }
    }
}

void displayStudents(const std::vector<Student>& students) {
    std::cout << "\nSorted Student Records (by GPA in descending order):\n";
    std::cout << "----------------------------------------------\n";
    std::cout << std::left << std::setw(30) << "Name" << "GPA\n";
    std::cout << "----------------------------------------------\n";

    for (const auto& student : students) {
        std::cout << std::left << std::setw(30) << student.name
                  << std::fixed << std::setprecision(2) << student.gpa << std::endl;
    }

    std::cout << "----------------------------------------------\n";
    std::cout << "Total records: " << students.size() << std::endl;
