    private TreeMap<Integer, TreeSet<String>> scoreToPlayers;
    private Map<String, Integer> playerToScore;
    private TreeMap<Integer, Integer> rankMap; // Maps score to its rank position
    private int totalPlayers;

    public GameLeaderboard() {
        scoreToPlayers = new TreeMap<>(Collections.reverseOrder()); // Descending order
        playerToScore = new HashMap<>();
        rankMap = new TreeMap<>(Collections.reverseOrder()); // Descending order
        totalPlayers = 0;
    }

    // O(log n) time complexity
    public void insertPlayerScore(String playerId, int score) {
        // Remove player's previous score if exists
        removePlayer(playerId);

        // Add new score
        playerToScore.put(playerId, score);

        // Update score to players mapping
        scoreToPlayers.putIfAbsent(score, new TreeSet<>());
        scoreToPlayers.get(score).add(playerId);

        // Update rank information
        updateRankMap(score, 1);
        totalPlayers++;
    }

    // O(log n) time complexity
    public void removePlayer(String playerId) {
        if (playerToScore.containsKey(playerId)) {
            int oldScore = playerToScore.get(playerId);

            // Update score to players mapping
            TreeSet<String> players = scoreToPlayers.get(oldScore);
            players.remove(playerId);

            if (players.isEmpty()) {
                scoreToPlayers.remove(oldScore);
            }

            // Update rank information
            updateRankMap(oldScore, -1);
            totalPlayers--;

            playerToScore.remove(playerId);
        }
    }

    // O(log n) time complexity
    private void updateRankMap(int score, int delta) {
        // Update the count for this score
        rankMap.put(score, rankMap.getOrDefault(score, 0) + delta);

        // Remove if count becomes zero
        if (rankMap.get(score) == 0) {
            rankMap.remove(score);
        }
    }

    // O(log n) time complexity
    public Integer getKthHighestScore(int k) {
        if (k <= 0 || k > totalPlayers) {
            return null;
        }

        int count = 0;
        for (Map.Entry<Integer, Integer> entry : rankMap.entrySet()) {
            count += entry.getValue();
            if (count >= k) {
                return entry.getKey();
            }
        }

        return null;
    }

