        int score;
        int count;  // Number of players with this score
        int leftSize;  // Size of left subtree
        ScoreNode left, right;

        public ScoreNode(int score) {
            this.score = score;
            this.count = 1;
            this.leftSize = 0;
            this.left = null;
            this.right = null;
        }
    }

    private ScoreNode root;
    private Map<String, Integer> playerToScore;
    private Map<Integer, Set<String>> scoreToPlayers;
    private int totalPlayers;

    public GameLeaderboard() {
        root = null;
        playerToScore = new HashMap<>();
        scoreToPlayers = new HashMap<>();
        totalPlayers = 0;
    }

    // O(log n) time complexity
    public void insertPlayerScore(String playerId, int score) {
        // Remove player's previous score if exists
        removePlayer(playerId);

        // Add new player-score mapping
        playerToScore.put(playerId, score);

        // Update score-players mapping
        scoreToPlayers.putIfAbsent(score, new HashSet<>());
        scoreToPlayers.get(score).add(playerId);

        // Insert score into the BST
        root = insert(root, score);
        totalPlayers++;
    }

    // O(log n) time complexity
    private ScoreNode insert(ScoreNode node, int score) {
        if (node == null) {
            return new ScoreNode(score);
        }

        if (score == node.score) {
            node.count++;
            return node;
        }

        if (score > node.score) {
            node.right = insert(node.right, score);
        } else {
            node.leftSize++;
            node.left = insert(node.left, score);
        }

        return balanceNode(node);
    }

    // O(log n) time complexity
    public void removePlayer(String playerId) {
        if (!playerToScore.containsKey(playerId)) {
            return;
        }

        int score = playerToScore.get(playerId);

        // Update score-players mapping
        Set<String> players = scoreToPlayers.get(score);
        players.remove(playerId);

        if (players.isEmpty()) {
            scoreToPlayers.remove(score);
            // Remove score from BST
            root = remove(root, score);
        } else {
            // Decrease count for this score
            decreaseCount(root, score);
        }

        playerToScore.remove(playerId);
        totalPlayers--;
    }

    // O(log n) time complexity
    private ScoreNode remove(ScoreNode node, int score) {
        if (node == null) {
            return null;
        }

        if (score > node.score) {
            node.right = remove(node.right, score);
        } else if (score < node.score) {
            node.leftSize--;
            node.left = remove(node.left, score);
        } else {
            // Node with only one child or no child
            if (node.left == null) {
                return node.right;
            } else if (node.right == null) {
                return node.left;
            }

            // Node with two children
            // Get the inorder successor (smallest in the right subtree)
            node.score = minValue(node.right);
            // Update the count
            node.count = getCount(root, node.score);
            // Delete the inorder successor
            node.right = remove(node.right, node.score);
        }

        return balanceNode(node);
    }

    // O(log n) time complexity
    private void decreaseCount(ScoreNode node, int score) {
        if (node == null) {
            return;
        }

        if (node.score == score) {
            node.count--;
            return;
        }

        if (score > node.score) {
            decreaseCount(node.right, score);
        } else {
            decreaseCount(node.left, score);
        }
    }

    // O(log n) time complexity
    private int minValue(ScoreNode node) {
        int minValue = node.score;
        while (node.left != null) {
            minValue = node.left.score;
            node = node.left;
        }
        return minValue;
    }

    // O(log n) time complexity
    private int getCount(ScoreNode node, int score) {
        if (node == null) {
            return 0;
        }

        if (node.score == score) {
            return node.count;
        }

        if (score > node.score) {
            return getCount(node.right, score);
        } else {
            return getCount(node.left, score);
        }
    }

    // Balance node to maintain O(log n) height
    private ScoreNode balanceNode(ScoreNode node) {
        // This is a simplified balancing - a full implementation would use AVL or Red-Black tree
        // For this example, we're assuming the tree remains relatively balanced
        return node;
    }

    // O(log n) time complexity
    public Integer getKthHighestScore(int k) {
        if (k <= 0 || k > totalPlayers) {
            return null;
        }

        return findKthLargest(root, k);
    }

    // O(log n) time complexity
    private Integer findKthLargest(ScoreNode node, int k) {
        if (node == null) {
            return null;
        }

        // Calculate the size of right subtree plus current node
        int rightSize = (node.right == null ? 0 : getSize(node.right)) + node.count;

        if (k <= rightSize) {
            // k-th largest is in the right subtree or is the current node
            if (k <= node.count) {
                return node.score;
            } else {
                return findKthLargest(node.right, k - node.count);
            }
        } else {
            // k-th largest is in the left subtree
            return findKthLargest(node.left, k - rightSize);
        }
    }

    // O(log n) time complexity
    private int getSize(ScoreNode node) {
        if (node == null) {
            return 0;
        }
        return node.leftSize + node.count + (node.right == null ? 0 : getSize(node.right));
    }

    public static void main(String[] args) {
        GameLeaderboard leaderboard = new GameLeaderboard();

        leaderboard.insertPlayerScore("player1", 100);
        leaderboard.insertPlayerScore("player2", 90);
        leaderboard.insertPlayerScore("player3", 85);
        leaderboard.insertPlayerScore("player4", 110);
        leaderboard.insertPlayerScore("player5", 95);

        System.out.println("1st highest score: " + leaderboard.getKthHighestScore(1));
        System.out.println("3rd highest score: " + leaderboard.getKthHighestScore(3));

        leaderboard.removePlayer("player4");
        System.out.println("1st highest score after removing player4: " + leaderboard.getKthHighestScore(1));

        leaderboard.insertPlayerScore("player1", 120);
        System.out.println("1st highest score after updating player1: " + leaderboard.getKthHighestScore(1));
    }
