class SkipListNode {
public:
    std::string stockSymbol;
    double price;
    std::vector<SkipListNode*> forward;

    SkipListNode(std::string symbol, double stockPrice, int level) : 
        stockSymbol(symbol), price(stockPrice), forward(level + 1, nullptr) {}
};

class StockPriceTracker {
private:
    static const int MAX_LEVEL = 16;
    static constexpr float PROBABILITY = 0.5;
    int level;
    SkipListNode* header;
    std::mt19937 gen;
    std::uniform_real_distribution<> dis;

    int randomLevel() {
        int lvl = 0;
        while (dis(gen) < PROBABILITY && lvl < MAX_LEVEL - 1) {
            lvl++;
        }
        return lvl;
    }

public:
    StockPriceTracker() : level(0), gen(time(nullptr)), dis(0.0, 1.0) {
        header = new SkipListNode("", 0.0, MAX_LEVEL);
    }

    ~StockPriceTracker() {
        SkipListNode* current = header;
        while (current->forward[0]) {
            SkipListNode* next = current->forward[0];
            delete current;
            current = next;
        }
        delete current;
    }

    void insert(std::string symbol, double price) {
        std::vector<SkipListNode*> update(MAX_LEVEL + 1, nullptr);
        SkipListNode* current = header;

        for (int i = level; i >= 0; i--) {
            while (current->forward[i] && 
                  (current->forward[i]->price < price || 
                  (current->forward[i]->price == price && 
                   current->forward[i]->stockSymbol < symbol))) {
                current = current->forward[i];
            }
            update[i] = current;
        }

        current = current->forward[0];

        if (current && current->stockSymbol == symbol) {
            current->price = price;  // Update existing stock price
        } else {
            int newLevel = randomLevel();

            if (newLevel > level) {
                for (int i = level + 1; i <= newLevel; i++) {
                    update[i] = header;
                }
                level = newLevel;
            }

            current = new SkipListNode(symbol, price, newLevel);

            for (int i = 0; i <= newLevel; i++) {
                current->forward[i] = update[i]->forward[i];
                update[i]->forward[i] = current;
            }
        }
    }

    bool remove(std::string symbol) {
        std::vector<SkipListNode*> update(MAX_LEVEL + 1, nullptr);
        SkipListNode* current = header;

        for (int i = level; i >= 0; i--) {
            while (current->forward[i] && current->forward[i]->stockSymbol < symbol) {
                current = current->forward[i];
            }
            update[i] = current;
        }

        current = current->forward[0];

        if (!current || current->stockSymbol != symbol) {
            return false;  // Stock not found
        }

        for (int i = 0; i <= level; i++) {
            if (update[i]->forward[i] != current) {
                break;
            }
            update[i]->forward[i] = current->forward[i];
        }

        delete current;

        // Update level if needed
        while (level > 0 && header->forward[level] == nullptr) {
            level--;
        }

        return true;
    }

    double search(std::string symbol) {
        SkipListNode* current = header;

        for (int i = level; i >= 0; i--) {
            while (current->forward[i] && current->forward[i]->stockSymbol < symbol) {
                current = current->forward[i];
            }
        }

        current = current->forward[0];

        if (current && current->stockSymbol == symbol) {
            return current->price;
        }

        return -1.0;  // Stock not found
    }

    std::vector<std::pair<std::string, double>> getSortedStocksByPrice() {
        std::vector<std::pair<std::string, double>> result;
        SkipListNode* current = header->forward[0];

        while (current) {
            result.push_back({current->stockSymbol, current->price});
            current = current->forward[0];
        }

        return result;
    }

    void displayAll() {
        SkipListNode* current = header->forward[0];
        std::cout << "\nCurrent Stock Prices (sorted by price):\n";
        std::cout << "-----------------------------------------\n";
        std::cout << std::left << std::setw(10) << "Symbol" << std::setw(10) << "Price" << std::endl;
        std::cout << "-----------------------------------------\n";

        while (current) {
            std::cout << std::left << std::setw(10) << current->stockSymbol 
                      << "$" << std::fixed << std::setprecision(2) << current->price << std::endl;
            current = current->forward[0];
        }
        std::cout << "-----------------------------------------\n";
    }
};

int main() {
    StockPriceTracker tracker;

    // Insert some initial stocks
    tracker.insert("AAPL", 198.11);
    tracker.insert("MSFT", 337.94);
    tracker.insert("GOOGL", 138.21);
    tracker.insert("AMZN", 145.24);
    tracker.insert("META", 326.49);

    tracker.displayAll();

    // Look up a stock price
    std::string symbol = "AAPL";
    double price = tracker.search(symbol);
    if (price >= 0) {
        std::cout << "Price of " << symbol << ": $" << std::fixed << std::setprecision(2) << price << std::endl;
    } else {
        std::cout << symbol << " not found in the tracker." << std::endl;
    }

    // Update a stock price
    tracker.insert("AAPL", 205.33);
    std::cout << "\nAfter updating AAPL price:";
    tracker.displayAll();

    // Remove a stock
    if (tracker.remove("GOOGL")) {
        std::cout << "\nAfter removing GOOGL:";
        tracker.displayAll();
    }

    // Get sorted list of stocks by price
    std::cout << "\nSorted list of stocks by price:\n";
    auto sortedStocks = tracker.getSortedStocksByPrice();
    for (const auto& stock : sortedStocks) {
        std::cout << stock.first << ": $" << std::fixed << std::setprecision(2) << stock.second << std::endl;
    }

    return 0;
}

use std::collections::BinaryHeap;
use std::cmp::{Ordering, Reverse};
use std::time::{Duration, Instant};

#[derive(Debug, Clone, Eq)]
struct Task {
    id: u32,
    drone_id: u32,
    description: String,
    urgency: u8,
    resource_requirement: f32,
    resource_availability: f32,
    created_at: Instant,
    deadline: Option<Instant>,
}

impl Task {
    fn new(id: u32, drone_id: u32, description: &str, urgency: u8, 
           resource_requirement: f32, resource_availability: f32, 
           deadline: Option<Duration>) -> Self {
        let created_at = Instant::now();
        let deadline = deadline.map(|d| created_at + d);

        Task {
            id,
            drone_id,
            description: description.to_string(),
            urgency,
            resource_requirement,
            resource_availability,
            created_at,
            deadline,
        }
    }

    fn calculate_priority(&self) -> f32 {
        let time_factor = match self.deadline {
            Some(deadline) => {
                let remaining = deadline.checked_duration_since(Instant::now())
                    .unwrap_or(Duration::from_secs(0));
                let remaining_secs = remaining.as_secs_f32();
                if remaining_secs <= 0.0 {
                    100.0 // Overdue tasks get maximum priority
                } else {
                    100.0 / remaining_secs.max(1.0)
                }
            },
            None => 1.0, // No deadline means lower time pressure
        };

        let resource_factor = if self.resource_availability >= self.resource_requirement {
            2.0 // Resources available
        } else {
            0.5 // Limited resources
        };

        (self.urgency as f32) * time_factor * resource_factor
    }
}

impl PartialEq for Task {
    fn eq(&self, other: &Self) -> bool {
        self.id == other.id
    }
}

impl PartialOrd for Task {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for Task {
    fn cmp(&self, other: &Self) -> Ordering {
        // First compare by priority (higher priority comes first)
        let self_priority = self.calculate_priority();
        let other_priority = other.calculate_priority();

        match self_priority.partial_cmp(&other_priority) {
            Some(Ordering::Equal) => {},
            Some(order) => return order.reverse(), // Reverse for max-heap
            None => {} // Handle potential NaN, continue to next comparison
        }

        // If priorities are equal, compare by creation time (older first)
        self.created_at.cmp(&other.created_at)
    }
}

struct DroneTaskScheduler {
    tasks: BinaryHeap<Task>,
    task_counter: u32,
}

impl DroneTaskScheduler {
    fn new() -> Self {
        DroneTaskScheduler {
            tasks: BinaryHeap::new(),
            task_counter: 0,
        }
    }

    fn add_task(&mut self, drone_id: u32, description: &str, urgency: u8, 
                resource_requirement: f32, resource_availability: f32,
                deadline: Option<Duration>) -> u32 {
        self.task_counter += 1;
        let task = Task::new(
            self.task_counter, 
            drone_id, 
            description, 
            urgency, 
            resource_requirement,
            resource_availability,
            deadline
        );
        self.tasks.push(task);
        self.task_counter
    }

    fn get_highest_priority_task(&mut self) -> Option<Task> {
        self.tasks.pop()
    }

    fn peek_highest_priority_task(&self) -> Option<&Task> {
        self.tasks.peek()
    }

    fn update_resource_availability(&mut self, task_id: u32, new_availability: f32) -> bool {
        let mut found_task = None;

        // Remove the task from heap if it exists
        let mut temp_heap = BinaryHeap::new();
        while let Some(task) = self.tasks.pop() {
            if task.id == task_id {
                let mut updated_task = task;
                updated_task.resource_availability = new_availability;
                found_task = Some(updated_task);
            } else {
                temp_heap.push(task);
            }
        }

        // Restore all tasks back to the heap
        self.tasks = temp_heap;

        // Push the updated task if found
        if let Some(task) = found_task {
            self.tasks.push(task);
            true
        } else {
            false
        }
    }

    fn get_tasks_for_drone(&self, drone_id: u32) -> Vec<&Task> {
        self.tasks.iter()
            .filter(|task| task.drone_id == drone_id)
            .collect()
    }

    fn task_count(&self) -> usize {
        self.tasks.len()
    }
}

fn main() {
    let mut scheduler = DroneTaskScheduler::new();

    // Add sample tasks
    scheduler.add_task(
        1, 
        "Take aerial image of target area", 
        8, 
        5.0, 
        7.0, 
        Some(Duration::from_secs(30))
    );

    scheduler.add_task(
        2, 
        "Deliver package to rooftop", 
        5, 
        3.0,
        2.0, 
        Some(Duration::from_secs(120))
    );

    scheduler.add_task(
        1, 
        "Return to charging station", 
        9, 
        1.0, 
        10.0, 
        Some(Duration::from_secs(10))
    );

    // Simulate task execution
    println!("Starting drone task simulation with {} tasks", scheduler.task_count());

    while let Some(task) = scheduler.get_highest_priority_task() {
        println!("Executing task: {} (Drone: {}, Priority: {})", 
                 task.description, 
                 task.drone_id,
                 task.calculate_priority());

        // Simulate task execution
        std::thread::sleep(Duration::from_millis(500));
    }

    println!("All tasks completed!");
}

import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.multipart.MultipartFile;

import java.io.IOException;
import java.util.Base64;

@RestController
@RequestMapping("/api/documents")
public class DocumentTransmissionService {

    @PostMapping("/upload")
    public ResponseEntity<DocumentResponse> uploadDocument(@RequestParam("file") MultipartFile file) {
        try {
            // Read file content
            byte[] fileContent = file.getBytes();

            // Encode content using Base64 - O(n) time complexity
            String encodedContent = Base64.getEncoder().encodeToString(fileContent);

            // Create and return response
            DocumentResponse response = new DocumentResponse(
                file.getOriginalFilename(), 
                file.getContentType(), 
                fileContent.length,
                encodedContent
            );

            return ResponseEntity.ok(response);
        } catch (IOException e) {
            return ResponseEntity.badRequest().build();
        }
    }

    public static class DocumentResponse {
        private String filename;
        private String contentType;
        private long originalSize;
        private String encodedContent;

        public DocumentResponse(String filename, String contentType, long originalSize, String encodedContent) {
            this.filename = filename;
            this.contentType = contentType;
            this.originalSize = originalSize;
            this.encodedContent = encodedContent;
        }

        // Getters and setters
        public String getFilename() { return filename; }
        public void setFilename(String filename) { this.filename = filename; }

        public String getContentType() { return contentType; }
        public void setContentType(String contentType) { this.contentType = contentType; }

        public long getOriginalSize() { return originalSize; }
        public void setOriginalSize(long originalSize) { this.originalSize = originalSize; }

        public String getEncodedContent() { return encodedContent; }
        public void setEncodedContent(String encodedContent) { this.encodedContent = encodedContent; }
    }
}

class Node {
  constructor(score, users = []) {
    this.score = score;
    this.users = users;
    this.left = null;
    this.right = null;
    this.height = 1;
    this.size = users.length;
  }
}

class LeaderboardAVL {
  constructor() {
    this.root = null;
    this.userMap = new Map();
  }

  getHeight(node) {
    return node ? node.height : 0;
  }

  getSize(node) {
    return node ? node.size : 0;
  }

  getBalanceFactor(node) {
    return node ? this.getHeight(node.left) - this.getHeight(node.right) : 0;
  }

  updateHeightAndSize(node) {
    node.height = Math.max(this.getHeight(node.left), this.getHeight(node.right)) + 1;
    node.size = node.users.length + this.getSize(node.left) + this.getSize(node.right);
  }

  rotateRight(y) {
    const x = y.left;
    const T2 = x.right;

    x.right = y;
    y.left = T2;

    this.updateHeightAndSize(y);
    this.updateHeightAndSize(x);

    return x;
  }

  rotateLeft(x) {
    const y = x.right;
    const T2 = y.left;

    y.left = x;
    x.right = T2;

    this.updateHeightAndSize(x);
    this.updateHeightAndSize(y);

    return y;
  }

  insert(root, score, userId) {
    if (!root) {
      return new Node(score, [userId]);
    }

    if (score === root.score) {
      root.users.push(userId);
      root.size++;
      return root;
    }

    if (score < root.score) {
      root.left = this.insert(root.left, score, userId);
    } else {
      root.right = this.insert(root.right, score, userId);
    }

    this.updateHeightAndSize(root);

    const balanceFactor = this.getBalanceFactor(root);

    // Left Left Case
    if (balanceFactor > 1 && score < root.left.score) {
      return this.rotateRight(root);
    }

    // Right Right Case
    if (balanceFactor < -1 && score > root.right.score) {
      return this.rotateLeft(root);
    }

    // Left Right Case
    if (balanceFactor > 1 && score > root.left.score) {
      root.left = this.rotateLeft(root.left);
      return this.rotateRight(root);
    }

    // Right Left Case
    if (balanceFactor < -1 && score < root.right.score) {
      root.right = this.rotateRight(root.right);
      return this.rotateLeft(root);
    }

    return root;
  }

  deleteNode(root, score, userId) {
    if (!root) return null;

    if (score < root.score) {
      root.left = this.deleteNode(root.left, score, userId);
    } else if (score > root.score) {
      root.right = this.deleteNode(root.right, score, userId);
    } else {
      // Found the node with the score
      const index = root.users.indexOf(userId);
      if (index !== -1) {
        root.users.splice(index, 1);
        root.size--;

        // If no users are left at this score, remove the node
        if (root.users.length === 0) {
          if (!root.left) {
            return root.right;
          } else if (!root.right) {
            return root.left;
          }

          // Node with two children
          const temp = this.findMinNode(root.right);
          root.score = temp.score;
          root.users = temp.users.slice();
          root.right = this.deleteNode(root.right, temp.score, temp.users[0]);
        } else {
          this.updateHeightAndSize(root);
          return root;
        }
      }
    }

    if (!root) return null;

    this.updateHeightAndSize(root);

    const balanceFactor = this.getBalanceFactor(root);

    // Left Left Case
    if (balanceFactor > 1 && this.getBalanceFactor(root.left) >= 0) {
      return this.rotateRight(root);
    }

    // Left Right Case
    if (balanceFactor > 1 && this.getBalanceFactor(root.left) < 0) {
      root.left = this.rotateLeft(root.left);
      return this.rotateRight(root);
    }

    // Right Right Case
    if (balanceFactor < -1 && this.getBalanceFactor(root.right) <= 0) {
      return this.rotateLeft(root);
    }

    // Right Left Case
    if (balanceFactor < -1 && this.getBalanceFactor(root.right) > 0) {
      root.right = this.rotateRight(root.right);
      return this.rotateLeft(root);
    }

    return root;
  }

  findMinNode(node) {
    let current = node;
    while (current.left) {
      current = current.left;
    }
    return current;
  }

  getRank(root, score, userId) {
    if (!root) return 0;

    if (score > root.score) {
      return this.getSize(root.left) + root.users.length + this.getRank(root.right, score, userId);
    } else if (score < root.score) {
      return this.getRank(root.left, score, userId);
    } else {
      // When we find the score node, we need to count users with same score but ahead of userId
      const index = root.users.indexOf(userId);
      return this.getSize(root.left) + (index !== -1 ? index : 0);
    }
  }

  getScoreFromRank(root, rank) {
    if (!root) return null;

    const leftSize = this.getSize(root.left);

    if (rank < leftSize) {
      return this.getScoreFromRank(root.left, rank);
    } else if (rank < leftSize + root.users.length) {
      return {
        score: root.score,
        userId: root.users[rank - leftSize]
      };
    } else {
      return this.getScoreFromRank(root.right, rank - leftSize - root.users.length);
    }
  }

  // Public API methods
  updateScore(userId, newScore) {
    // Remove the user from their previous score if they exist in the leaderboard
    if (this.userMap.has(userId)) {
      const oldScore = this.userMap.get(userId);
      this.root = this.deleteNode(this.root, oldScore, userId);
    }

    // Add the user with their new score
    this.root = this.insert(this.root, newScore, userId);
    this.userMap.set(userId, newScore);

    return this;
  }

  getUserRank(userId) {
    if (!this.userMap.has(userId)) {
      return -1; // User not found
    }

    const score = this.userMap.get(userId);
    // Get rank (0-indexed)
    const rank = this.getRank(this.root, score, userId);
    // Return 1-indexed rank
    return this.getSize(this.root) - rank;
  }

  getUsersAtRank(rank) {
    if (rank <= 0 || rank > this.getSize(this.root)) {
      return null;
    }

    // Convert to 0-indexed for internal processing
    const zeroIndexedRank = this.getSize(this.root) - rank;
    return this.getScoreFromRank(this.root, zeroIndexedRank);
  }

  getTopUsers(count) {
    const result = [];
    const totalUsers = this.getSize(this.root);
    const maxToRetrieve = Math.min(count, totalUsers);

    for (let i = 1; i <= maxToRetrieve; i++) {
      const user = this.getUsersAtRank(i);
      if (user) {
        result.push({
          rank: i,
          userId: user.userId,
          score: user.score
        });
      }
    }

    return result;
  }

  getTotalUsers() {
    return this.getSize(this.root);
  }
}

