#include <iostream>
#include <map>
#include <string>
#include <vector>
#include <stdexcept>

enum Side {
    BUY,
    SELL
};

class Order {
public:
    std::string orderId;
    double price;
    int quantity;
    Side side;
    std::string timestamp;

    Order(const std::string& id, double p, int qty, Side s, const std::string& time)
        : orderId(id), price(p), quantity(qty), side(s), timestamp(time) {
        validate();
    }

    void validate() const {
        if (price <= 0) throw std::invalid_argument("Price must be positive");
        if (quantity <= 0) throw std::invalid_argument("Quantity must be positive");
    }
};

class PriceLevel {
public:
    double price;
    std::vector<Order> orders;
    int totalQuantity;

    PriceLevel(double p) : price(p), totalQuantity(0) {}

    void addOrder(const Order& order) {
        orders.push_back(order);
        totalQuantity += order.quantity;
    }

    bool removeOrder(const std::string& orderId) {
        for (auto it = orders.begin(); it != orders.end(); ++it) {
            if (it->orderId == orderId) {
                totalQuantity -= it->quantity;
                orders.erase(it);
                return true;
            }
        }
        return false;
    }
};

class OrderBook {
private:
    std::map<double, PriceLevel> buyLevels;  // Descending order
    std::map<double, PriceLevel> sellLevels; // Ascending order

public:
    bool addOrder(const Order& order) {
        try {
            order.validate();
            auto& levels = (order.side == BUY) ? buyLevels : sellLevels;

            auto it = levels.find(order.price);
            if (it == levels.end()) {
                levels.emplace(order.price, PriceLevel(order.price));
                it = levels.find(order.price);
            }

            it->second.addOrder(order);
            return true;
        } catch (const std::exception& e) {
            std::cerr << "Error adding order: " << e.what() << std::endl;
            return false;
        }
    }

    bool cancelOrder(const std::string& orderId, double price, Side side) {
        auto& levels = (side == BUY) ? buyLevels : sellLevels;
        auto it = levels.find(price);

        if (it == levels.end()) {
            return false;
        }

        bool result = it->second.removeOrder(orderId);

        // Remove price level if empty
        if (result && it->second.orders.empty()) {
            levels.erase(it);
        }

        return result;
    }

    std::vector<PriceLevel> getTopPriceLevels(Side side, int numLevels) const {
        std::vector<PriceLevel> result;
        const auto& levels = (side == BUY) ? buyLevels : sellLevels;

        auto it = levels.begin();
        while (it != levels.end() && numLevels > 0) {
            result.push_back(it->second);
            ++it;
            --numLevels;
        }

        return result;
    }

    PriceLevel* getPriceLevel(double price, Side side) {
        auto& levels = (side == BUY) ? buyLevels : sellLevels;
        auto it = levels.find(price);

        if (it != levels.end()) {
            return &(it->second);
        }

        return nullptr;
    }

    double getBestBid() const {
        return buyLevels.empty() ? 0 : buyLevels.begin()->first;
    }

    double getBestAsk() const {
        return sellLevels.empty() ? 0 : sellLevels.begin()->first;
    }

    double getSpread() const {
        if (buyLevels.empty() || sellLevels.empty()) {
            return -1; // Indicates no valid spread
        }
        return sellLevels.begin()->first - buyLevels.begin()->first;
    }
};

int main() {
    OrderBook orderBook;

    // Add sample orders
    orderBook.addOrder(Order("1", 100.5, 200, BUY, "2023-01-01 10:00:00"));
    orderBook.addOrder(Order("2", 100.3, 150, BUY, "2023-01-01 10:00:01"));
    orderBook.addOrder(Order("3", 100.7, 300, SELL, "2023-01-01 10:00:02"));
    orderBook.addOrder(Order("4", 100.8, 100, SELL, "2023-01-01 10:00:03"));

    // Display best bid/ask
    std::cout << "Best bid: " << orderBook.getBestBid() << std::endl;
    std::cout << "Best ask: " << orderBook.getBestAsk() << std::endl;
    std::cout << "Spread: " << orderBook.getSpread() << std::endl;

    return 0;
}

use std::collections::HashMap;
use std::fs::File;
use std::io::{self, BufRead};
use std::path::Path;

struct TrieNode {
    is_end_of_word: bool,
    children: HashMap<char, TrieNode>,
}

impl TrieNode {
    fn new() -> Self {
        TrieNode {
            is_end_of_word: false,
            children: HashMap::new(),
        }
    }
}

struct Trie {
    root: TrieNode,
}

impl Trie {
    fn new() -> Self {
        Trie {
            root: TrieNode::new(),
        }
    }

    fn insert(&mut self, word: &str) {
        let mut current = &mut self.root;

        for c in word.chars() {
            current = current.children.entry(c).or_insert_with(TrieNode::new);
        }
        current.is_end_of_word = true;
    }

    fn search(&self, word: &str) -> bool {
        let mut current = &self.root;

        for c in word.chars() {
            match current.children.get(&c) {
                Some(node) => current = node,
                None => return false,
            }
        }
        current.is_end_of_word
    }

    fn starts_with(&self, prefix: &str) -> bool {
        let mut current = &self.root;

        for c in prefix.chars() {
            match current.children.get(&c) {
                Some(node) => current = node,
                None => return false,
            }
        }
        true
    }

    fn get_all_with_prefix(&self, prefix: &str) -> Vec<String> {
        let mut result = Vec::new();

        // Handle empty prefix
        if prefix.is_empty() {
            self.collect_all_words(&self.root, &String::new(), &mut result);
            return result;
        }

        let mut current = &self.root;
        for c in prefix.chars() {
            match current.children.get(&c) {
                Some(node) => current = node,
                None => return result, // Prefix not found
            }
        }

        self.collect_all_words(current, prefix, &mut result);
        result
    }

    fn collect_all_words(&self, node: &TrieNode, prefix: &str, result: &mut Vec<String>) {
        if node.is_end_of_word {
            result.push(prefix.to_string());
        }

        for (c, child) in &node.children {
            let mut new_prefix = prefix.to_string();
            new_prefix.push(*c);
            self.collect_all_words(child, &new_prefix, result);
        }
    }
}

fn load_dictionary(file_path: &str, trie: &mut Trie) -> io::Result<()> {
    let path = Path::new(file_path);
    let file = File::open(path)?;
    let reader = io::BufReader::new(file);

    for line in reader.lines() {
        let word = line?;
        if !word.is_empty() && word.is_ascii() {
            trie.insert(&word.trim().to_lowercase());
        }
    }

    Ok(())
}

fn main() -> io::Result<()> {
    let mut trie = Trie::new();

    // Load dictionary from file
    let dictionary_file = "dictionary.txt";
    match load_dictionary(dictionary_file, &mut trie) {
        Ok(_) => println!("Dictionary loaded successfully."),
        Err(e) => println!("Error loading dictionary: {}", e),
    }

    // Example usage
    let prefix = "pro";
    let words = trie.get_all_with_prefix(prefix);

    println!("Words with prefix '{}': {:?}", prefix, words);

    Ok(())
}

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <math.h>

bool isPrime(int number) {
    if (number <= 1)
        return false;
    if (number <= 3)
        return true;
    if (number % 2 == 0 || number % 3 == 0)
        return false;

    int limit = sqrt(number);
    for (int i = 5; i <= limit; i += 6) {
        if (number % i == 0 || number % (i + 2) == 0)
            return false;
    }
    return true;
}

int main() {
    FILE *file = fopen("numbers.txt", "r");
    if (file == NULL) {
        printf("Error opening file.\n");
        return 1;
    }

    int number;
    while (fscanf(file, "%d", &number) == 1) {
        if (number <= 0) {
            printf("%d is not a positive integer.\n", number);
        } else {
            printf("%d is %s.\n", number, isPrime(number) ? "prime" : "not prime");
        }
    }

    fclose(file);
    return 0;
}

use std::collections::HashMap;
use std::ptr::NonNull;
use std::sync::{Arc, Mutex};
use std::thread;

// Node in our intrusive doubly linked list
struct Node {
    task: Task,
    next: Option<NonNull<Node>>,
    prev: Option<NonNull<Node>>,
}

impl Node {
    fn new(task: Task) -> Self {
        Node {
            task,
            next: None,
            prev: None,
        }
    }
}

#[derive(Debug, Clone, Eq, PartialEq)]
struct Task {
    id: usize,
    description: String,
    priority: u32,
}

// Priority queue implemented as a hashmap of doubly linked lists
struct PriorityList {
    // Map priority levels to the head and tail of each list
    buckets: HashMap<u32, (NonNull<Node>, NonNull<Node>)>,
    // Map task IDs to their nodes for O(1) lookup
    task_map: HashMap<usize, NonNull<Node>>,
    // Track highest priority for O(1) access
    highest_priority: Option<u32>,
    // Next available task ID
    next_id: usize,
}

impl PriorityList {
    fn new() -> Self {
        PriorityList {
            buckets: HashMap::new(),
            task_map: HashMap::new(),
            highest_priority: None,
            next_id: 0,
        }
    }

    // Add a task with O(1) complexity
    fn add_task(&mut self, description: String, priority: u32) -> usize {
        let id = self.next_id;
        self.next_id += 1;

        let task = Task {
            id,
            description,
            priority,
        };

        // Create a new node
        let mut node = Box::new(Node::new(task));
        let node_ptr = NonNull::new(Box::into_raw(node)).unwrap();

        // Update highest priority in O(1)
        if self.highest_priority.is_none() || priority > self.highest_priority.unwrap() {
            self.highest_priority = Some(priority);
        }

        // Insert node into the correct priority bucket
        match self.buckets.get_mut(&priority) {
            Some((head, tail)) => {
                // Insert at the end of the list
                unsafe {
                    (*node_ptr.as_ptr()).prev = Some(*tail);
                    (*tail.as_ptr()).next = Some(node_ptr);
                    *tail = node_ptr;
                }
            }
            None => {
                // Create a new bucket with this node as both head and tail
                self.buckets.insert(priority, (node_ptr, node_ptr));
            }
        }

        // Map the task ID to its node for O(1) access later
        self.task_map.insert(id, node_ptr);

        id
    }

    // Remove a task with O(1) complexity
    fn remove_task(&mut self, id: usize) -> Option<Task> {
        // Find the node by ID - O(1)
        let node_ptr = self.task_map.remove(&id)?;

        // Get the task's priority
        let priority = unsafe { (*node_ptr.as_ptr()).task.priority };

        // Remove node from the linked list - O(1)
        unsafe {
            // Update adjacent nodes
            if let Some(prev) = (*node_ptr.as_ptr()).prev {
                (*prev.as_ptr()).next = (*node_ptr.as_ptr()).next;
            } else {
                // This was the head node of its bucket
                if let Some((head, tail)) = self.buckets.get_mut(&priority) {
                    if *head == node_ptr {
                        // Update head to next node
                        *head = (*node_ptr.as_ptr()).next.unwrap_or(*tail);
                    }
                }
            }

            if let Some(next) = (*node_ptr.as_ptr()).next {
                (*next.as_ptr()).prev = (*node_ptr.as_ptr()).prev;
            } else {
                // This was the tail node of its bucket
                if let Some((head, tail)) = self.buckets.get_mut(&priority) {
                    if *tail == node_ptr {
                        // Update tail to previous node
                        *tail = (*node_ptr.as_ptr()).prev.unwrap_or(*head);
                    }
                }
            }
        }

        // Check if the bucket is now empty
        let bucket_empty = if let Some((head, tail)) = self.buckets.get(&priority) {
            unsafe {
                // If head's prev and tail's next are both None, and they point to the same node,
                // then this was the only node in the bucket
                (*head.as_ptr()).prev.is_none() && 
                (*tail.as_ptr()).next.is_none() && 
                head == tail && 
                *head != node_ptr
            }
        } else {
            true
        };

        if bucket_empty {
            self.buckets.remove(&priority);

            // Update highest priority if needed - O(1) amortized
            if Some(priority) == self.highest_priority {
                self.highest_priority = self.buckets.keys().max().cloned();
            }
        }

        // Convert node back to Box and drop it safely
        let node = unsafe { Box::from_raw(node_ptr.as_ptr()) };
        Some(node.task)
    }

    // Get highest priority task with O(1) complexity
    fn get_highest_priority_task(&mut self) -> Option<Task> {
        let priority = self.highest_priority?;

        // Get the bucket with the highest priority
        let (head, tail) = self.buckets.get_mut(&priority)?;

        // Get the first node in the bucket (highest priority)
        let node_ptr = *head;

        // Remove the node from the linked list
        unsafe {
            // If there's a next node, it becomes the head
            if let Some(next) = (*node_ptr.as_ptr()).next {
                (*next.as_ptr()).prev = None;
                *head = next;
            } else {
                // This was the only node in the bucket
                self.buckets.remove(&priority);

                // Update highest priority
                self.highest_priority = self.buckets.keys().max().cloned();
            }
        }

        // Remove from task map
        let id = unsafe { (*node_ptr.as_ptr()).task.id };
        self.task_map.remove(&id);

        // Convert node back to Box and return the task
        let node = unsafe { Box::from_raw(node_ptr.as_ptr()) };
        Some(node.task)
    }

    // List all tasks in priority order - O(n) which is optimal
    fn list_tasks(&self) -> Vec<Task> {
        let mut result = Vec::with_capacity(self.task_map.len());

        // Get priorities in descending order
        let mut priorities: Vec<_> = self.buckets.keys().collect();
        priorities.sort_by(|a, b| b.cmp(a));

        // Iterate through priorities
        for &priority in &priorities {
            if let Some((head, _)) = self.buckets.get(priority) {
                // Traverse the linked list for this priority
                let mut current = Some(*head);
                while let Some(node_ptr) = current {
                    unsafe {
                        result.push((*node_ptr.as_ptr()).task.clone());
                        current = (*node_ptr.as_ptr()).next;
                    }
                }
            }
        }

        result
    }
}

// Thread-safe task manager wrapper
struct TaskManager {
    inner: Arc<Mutex<PriorityList>>,
}

impl TaskManager {
    fn new() -> Self {
        TaskManager {
            inner: Arc::new(Mutex::new(PriorityList::new())),
        }
    }

    fn add_task(&self, description: String, priority: u32) -> usize {
        let mut list = self.inner.lock().unwrap();
        list.add_task(description, priority)
    }

    fn remove_task(&self, id: usize) -> Option<Task> {
        let mut list = self.inner.lock().unwrap();
        list.remove_task(id)
    }

    fn get_highest_priority_task(&self) -> Option<Task> {
        let mut list = self.inner.lock().unwrap();
        list.get_highest_priority_task()
    }

    fn list_tasks(&self) -> Vec<Task> {
        let list = self.inner.lock().unwrap();
        list.list_tasks()
    }
}

impl Clone for TaskManager {
    fn clone(&self) -> Self {
        TaskManager {
            inner: Arc::clone(&self.inner),
        }
    }
}

fn main() {
    let task_manager = TaskManager::new();
    let mut handles = vec![];

    // Create multiple threads to add tasks
    for i in 0..10 {
        let tm = task_manager.clone();
        let handle = thread::spawn(move || {
            for j in 0..100 {
                let priority = (i * 100 + j) % 10;
                tm.add_task(format!("Task {}-{}", i, j), priority as u32);
            }
        });
        handles.push(handle);
    }

    // Wait for all threads to complete
    for handle in handles {
        handle.join().unwrap();
    }

    // Process the highest priority tasks
    for _ in 0..10 {
        if let Some(task) = task_manager.get_highest_priority_task() {
            println!("Processing: {:?}", task);
        }
    }
}

import java.util.BitSet;
import java.util.Scanner;

public class OrderManagementSystem {
    private BitSet orderIdSet;
    private final int MAX_ORDER_ID;

    public OrderManagementSystem(int maxOrderId) {
        this.MAX_ORDER_ID = maxOrderId;
        this.orderIdSet = new BitSet(maxOrderId);
    }

    public void insertOrder(int orderId) {
        if (orderId < 0 || orderId >= MAX_ORDER_ID) {
            throw new IllegalArgumentException("Order ID out of range: " + orderId);
        }
        orderIdSet.set(orderId);
    }

    public boolean containsOrder(int orderId) {
        if (orderId < 0 || orderId >= MAX_ORDER_ID) {
            return false;
        }
        return orderIdSet.get(orderId);
    }

    public void removeOrder(int orderId) {
        if (orderId < 0 || orderId >= MAX_ORDER_ID) {
            throw new IllegalArgumentException("Order ID out of range: " + orderId);
        }
        orderIdSet.clear(orderId);
    }

    public int getTotalOrders() {
        return orderIdSet.cardinality();
    }

    public static void main(String[] args) {
        int maxOrderId = 1_000_000; // Support for up to 1 million order IDs
        OrderManagementSystem orderSystem = new OrderManagementSystem(maxOrderId);
        Scanner scanner = new Scanner(System.in);
        boolean running = true;

        System.out.println("Order Management System");
        System.out.println("Commands: add <id>, check <id>, remove <id>, count, exit");

        while (running) {
            System.out.print("> ");
            String input = scanner.nextLine().trim();
            String[] parts = input.split("\\s+", 2);

            try {
                switch (parts[0].toLowerCase()) {
                    case "add":
                        int addId = Integer.parseInt(parts[1]);
                        orderSystem.insertOrder(addId);
                        System.out.println("Order " + addId + " added");
                        break;

                    case "check":
                        int checkId = Integer.parseInt(parts[1]);
                        boolean exists = orderSystem.containsOrder(checkId);
                        System.out.println("Order " + checkId + " " + (exists ? "exists" : "does not exist"));
                        break;

                    case "remove":
                        int removeId = Integer.parseInt(parts[1]);
                        orderSystem.removeOrder(removeId);
                        System.out.println("Order " + removeId + " removed");
                        break;

                    case "count":
                        System.out.println("Total orders: " + orderSystem.getTotalOrders());
                        break;

                    case "exit":
                        running = false;
                        break;

                    default:
                        System.out.println("Unknown command. Available commands: add, check, remove, count, exit");
                }
            } catch (NumberFormatException e) {
                System.out.println("Invalid order ID format");
            } catch (IllegalArgumentException e) {
                System.out.println(e.getMessage());
            } catch (ArrayIndexOutOfBoundsException e) {
                System.out.println("Missing order ID parameter");
            }
        }

        scanner.close();
        System.out.println("System terminated");
    }
}

#include <iostream>
#include <vector>
#include <string>
#include <limits>

struct Employee {
    std::string name;
    int id;
    double performanceScore;
};

void insertionSort(std::vector<Employee>& employees) {
    int n = employees.size();
    for (int i = 1; i < n; i++) {
        Employee key = employees[i];
        int j = i - 1;

        while (j >= 0 && employees[j].performanceScore > key.performanceScore) {
            employees[j + 1] = employees[j];
            j--;
        }
        employees[j + 1] = key;
    }
}

