            std::cout << "Please enter a valid performance score between 0.0 and 5.0: ";
        }
        std::cin.ignore(std::numeric_limits<std::streamsize>::max(), '\n');

        employees.push_back(emp);
    }

    insertionSort(employees);

    std::cout << "\nSorted Employee Records (by Performance Score):\n";
