class Player {
public:
    int id;
    std::string name;
    int score;

    Player(int id, const std::string& name, int score = 0)
        : id(id), name(name), score(score) {}
};

class Leaderboard {
private:
    std::map<int, Player> players; // playerId -> Player
    std::set<std::pair<int, int>, std::greater<std::pair<int, int>>> scoreBoard; // <score, playerId>

public:
    void addPlayer(const Player& player) {
        // O(log n) operations: map insertion and set insertion
        players[player.id] = player;
        scoreBoard.insert({player.score, player.id});
    }

    void updateScore(int playerId, int newScore) {
        // Check if player exists
        auto playerIt = players.find(playerId);
        if (playerIt == players.end()) {
            return;
        }

        // Get old score and remove the old entry from scoreBoard - O(log n)
        int oldScore = playerIt->second.score;
        scoreBoard.erase({oldScore, playerId});

        // Update player's score - O(1) as we already have the iterator
        playerIt->second.score = newScore;

        // Insert updated score into scoreBoard - O(log n)
        scoreBoard.insert({newScore, playerId});
    }

    void displayLeaderboard(int top = 10) {
        std::cout << "\n===== LEADERBOARD =====\n";
        std::cout << "Rank | ID | Player | Score\n";
        std::cout << "------------------------\n";

        int rank = 1;
        for (const auto& entry : scoreBoard) {
            if (rank > top) break;

            int score = entry.first;
            int playerId = entry.second;

            std::cout << rank << " | " 
                      << playerId << " | " 
                      << players[playerId].name << " | " 
                      << score << "\n";
            rank++;
        }
    }
};

int main() {
    Leaderboard leaderboard;

    // Add some players
    leaderboard.addPlayer(Player(1, "Alice"));
    leaderboard.addPlayer(Player(2, "Bob"));
    leaderboard.addPlayer(Player(3, "Charlie"));
    leaderboard.addPlayer(Player(4, "Dave"));
    leaderboard.addPlayer(Player(5, "Eve"));

    // Update scores
    leaderboard.updateScore(1, 100);
    leaderboard.updateScore(2, 80);
    leaderboard.updateScore(3, 150);
    leaderboard.updateScore(4, 80); // Same score as Bob, but will appear later due to ID
    leaderboard.updateScore(5, 120);

    // Display leaderboard
    leaderboard.displayLeaderboard();

    // Update scores again
    leaderboard.updateScore(1, 200);
    leaderboard.updateScore(4, 200); // Same score as Alice

    // Display updated leaderboard
    leaderboard.displayLeaderboard();

    return 0;
}

import heapq
import uuid

class Task:
    def __init__(self, priority, description):
        self.priority = priority
        self.description = description
        self.id = uuid.uuid4()  # Unique identifier for each task

    def __lt__(self, other):
        return self.priority < other.priority

    def __eq__(self, other):
        return self.id == other.id


class PriorityQueue:
    def __init__(self):
        self.heap = []
        self.task_set = set()  # For checking duplicates

    def insert(self, priority, description):
        # Validate input
        if not isinstance(priority, (int, float)):
            raise ValueError("Priority must be a number")
        if not description:
            raise ValueError("Task description cannot be empty")

        # Check for duplicate tasks
        if description in self.task_set:
            # Just update the priority by removing and reinserting
            self._remove_task_by_description(description)

        # Add new task
        task = Task(priority, description)
        heapq.heappush(self.heap, task)
        self.task_set.add(description)
        return task

    def _remove_task_by_description(self, description):
        # Find and remove the task with the given description
        for i, task in enumerate(self.heap):
            if task.description == description:
                self.heap.pop(i)
                self.task_set.remove(description)
                # Restore heap property
                heapq.heapify(self.heap)
                break

    def delete_min(self):
        if not self.heap:
            return None

        task = heapq.heappop(self.heap)
        self.task_set.remove(task.description)
        return task

    def peek_min(self):
        if not self.heap:
            return None
        return self.heap[0]

    def is_empty(self):
        return len(self.heap) == 0

    def size(self):
        return len(self.heap)

    def process_batch(self, tasks):
        """Process a batch of tasks with O(n log n) time complexity"""
        # Validate batch input
        if not isinstance(tasks, list):
            raise ValueError("Batch must be a list of (priority, description) tuples")

        # Pre-process tasks for batch insertion
        for priority, description in tasks:
            try:
                self.insert(priority, description)
            except ValueError as e:
                print(f"Skipping invalid task: {str(e)}")

        # Process tasks in order of priority
        results = []
        while not self.is_empty():
            results.append(self.delete_min())

        return results


