// Maintain heap property upward
void heapifyUp(PriorityQueue* queue, int index) {
    if (index == 0) return;

    int parent = (index - 1) / 2;

    // If current packet has higher priority than parent
    if (queue->packets[index]->priority > queue->packets[parent]->priority) {
        swap(&queue->packets[index], &queue->packets[parent]);
        heapifyUp(queue, parent);
    } else if (queue->packets[index]->priority == queue->packets[parent]->priority &&
               queue->packets[index]->arrival_time < queue->packets[parent]->arrival_time) {
        // If same priority, older packets go first (FIFO within same priority)
        swap(&queue->packets[index], &queue->packets[parent]);
        heapifyUp(queue, parent);
    }
}

