        (queue->packets[right]->priority > queue->packets[largest]->priority || 
        (queue->packets[right]->priority == queue->packets[largest]->priority && 
         queue->packets[right]->arrival_time < queue->packets[largest]->arrival_time))) {
        largest = right;
    }

    // If largest is not the current node, swap and continue heapifying
    if (largest != index) {
        swap(&queue->packets[index], &queue->packets[largest]);
        heapifyDown(queue, largest);
    }
}

// Add packet to priority queue - O(log n) operation
bool enqueue(PriorityQueue* queue, Packet* packet) {
    if (isFull(queue)) {
        logMessage("Error: Queue is full, packet dropped");
        return false;
    }

    // Add the packet at the end of the heap
    queue->packets[queue->size] = packet;

    // Restore the heap property
    heapifyUp(queue, queue->size);

    queue->size++;

    char log_message[100];
    sprintf(log_message, "Enqueued packet ID: %d with priority %d", packet->id, packet->priority);
    logMessage(log_message);

    return true;
}

// Remove highest priority packet from queue - O(log n) operation
Packet* dequeue(PriorityQueue* queue) {
    if (isEmpty(queue)) {
        logMessage("Error: Attempted to dequeue from empty queue");
        return NULL;
    }

    // Get the highest priority packet (root of heap)
    Packet* highestPriorityPacket = queue->packets[0];

    // Replace root with the last element
    queue->packets[0] = queue->packets[queue->size - 1];
    queue->size--;

    // Restore heap property if queue is not empty
    if (!isEmpty(queue)) {
        heapifyDown(queue, 0);
    }

    char log_message[100];
    sprintf(log_message, "Dequeued packet ID: %d with priority %d", highestPriorityPacket->id, highestPriorityPacket->priority);
    logMessage(log_message);

    return highestPriorityPacket;
}

// Create a new packet
Packet* createPacket(int id, Priority priority, size_t size, const char* payload) {
    // Validate packet before creation
    if (!validatePacket(id, priority, size, payload)) {
        return NULL;
    }

    Packet* packet = (Packet*)malloc(sizeof(Packet));
    if (packet == NULL) {
        logMessage("Error: Memory allocation failed for packet");
        return NULL;
    }

    packet->id = id;
    packet->priority = priority;
    packet->size = size;
    packet->arrival_time = time(NULL);

    packet->payload = (char*)malloc(size + 1);
    if (packet->payload == NULL) {
        logMessage("Error: Memory allocation failed for packet payload");
        free(packet);
        return NULL;
    }

    strncpy(packet->payload, payload, size);
    packet->payload[size] = '\0';

    return packet;
}

// Free packet memory
void freePacket(Packet* packet) {
    if (packet != NULL) {
        if (packet->payload != NULL) {
            free(packet->payload);
        }
        free(packet);
    }
}

// Log message to file for debugging
void logMessage(const char* message) {
    FILE* log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error: Could not open log file\n");
        return;
    }

    time_t now = time(NULL);
    char* timestamp = ctime(&now);
    timestamp[strlen(timestamp) - 1] = '\0';  // Remove newline

    fprintf(log_file, "[%s] %s\n", timestamp, message);
    fclose(log_file);

    // Also print to console for debugging
    printf("[LOG] %s\n", message);
}

// Validate packet data
bool validatePacket(int id, Priority priority, size_t size, const char* payload) {
    // Check ID is positive
    if (id < 0) {
        logMessage("Error: Invalid packet ID (must be positive)");
        return false;
    }

    // Check priority is valid
    if (priority < LOW || priority > CRITICAL) {
        logMessage("Error: Invalid priority level");
        return false;
    }

    // Check size is within limits
    if (size == 0 || size > MAX_PAYLOAD_SIZE) {
        logMessage("Error: Invalid payload size");
        return false;
    }

    // Check payload is not NULL
    if (payload == NULL) {
        logMessage("Error: Payload cannot be NULL");
        return false;
    }

    return true;
}

// Process packets in the queue
void processPackets(PriorityQueue* queue) {
    int processed = 0;

