    let mut input = String::new();
    io::stdin().read_line(&mut input).expect("Failed to read input");
    let n: usize = input.trim().parse().unwrap_or(8);

    let mut board = vec![vec![false; n]; n];
    let mut solutions = Vec::new();

    solve_n_queens(&mut board, 0, &mut solutions);

    println!("Found {} solutions for {}-Queens problem:", solutions.len(), n);
    for (i, solution) in solutions.iter().enumerate() {
        println!("Solution #{}:", i + 1);
        print_board(solution);
    }
}

fn solve_n_queens(board: &mut Vec<Vec<bool>>, row: usize, solutions: &mut Vec<Vec<Vec<bool>>>) {
    let n = board.len();
    if row == n {
        solutions.push(board.clone());
        return;
    }

    for col in 0..n {
        if is_safe(board, row, col) {
            board[row][col] = true;
            solve_n_queens(board, row + 1, solutions);
            board[row][col] = false;
        }
    }
}

fn is_safe(board: &Vec<Vec<bool>>, row: usize, col: usize) -> bool {
    let n = board.len();

    // Check column
    for i in 0..row {
        if board[i][col] {
            return false;
        }
    }

    // Check upper left diagonal
    let mut i = row as isize - 1;
    let mut j = col as isize - 1;
    while i >= 0 && j >= 0 {
        if board[i as usize][j as usize] {
            return false;
        }
        i -= 1;
        j -= 1;
    }

    // Check upper right diagonal
    let mut i = row as isize - 1;
    let mut j = col as isize + 1;
    while i >= 0 && j < n as isize {
        if board[i as usize][j as usize] {
            return false;
        }
        i -= 1;
        j += 1;
    }

    true
}

fn print_board(board: &Vec<Vec<bool>>) {
    let n = board.len();
    for i in 0..n {
        for j in 0..n {
            if board[i][j] {
                print!("Q ");
            } else {
                print!(". ");
            }
        }
        println!();
    }
    println!();
}

function shortestPath(graph, start, end) {
  // Input validation
  if (!graph || typeof graph !== 'object' || Object.keys(graph).length === 0) {
    throw new Error("Invalid graph: Graph must be a non-empty object");
  }

  if (!start || !graph.hasOwnProperty(start)) {
    throw new Error(`Invalid start intersection: ${start} does not exist`);
  }

  if (!end || !graph.hasOwnProperty(end)) {
    throw new Error(`Invalid end intersection: ${end} does not exist`);
  }

  // Get all vertices
  const vertices = Object.keys(graph);
  const V = vertices.length;

  // Initialize distances and previous nodes
  const distances = {};
  const previous = {};
  const visited = {};

  // Set initial distances to Infinity
  for (const vertex of vertices) {
    distances[vertex] = Infinity;
    previous[vertex] = null;
    visited[vertex] = false;
  }
  distances[start] = 0;

  // Main Dijkstra's algorithm loop - O(V²)
  for (let count = 0; count < V - 1; count++) {
    // Find vertex with minimum distance among unvisited vertices - O(V)
    let minDistance = Infinity;
    let u = null;

    for (const vertex of vertices) {
      if (!visited[vertex] && distances[vertex] <= minDistance) {
        minDistance = distances[vertex];
        u = vertex;
      }
    }

    // If no vertex found or unreachable
    if (u === null) break;

    // Mark as visited
    visited[u] = true;

    // If we reached the destination, we can break early
    if (u === end) break;

    // Update distances to adjacent vertices - O(V) in worst case
    if (graph[u]) {
      for (const [neighbor, weight] of Object.entries(graph[u])) {
        if (typeof weight !== 'number' || weight < 0) {
          throw new Error(`Invalid edge weight from ${u} to ${neighbor}`);
        }

        if (!visited[neighbor] && distances[u] !== Infinity) {
          const newDistance = distances[u] + weight;
          if (newDistance < distances[neighbor]) {
            distances[neighbor] = newDistance;
            previous[neighbor] = u;
          }
        }
      }
    }
  }

  // Check if destination is reachable
  if (distances[end] === Infinity) {
    throw new Error(`Destination ${end} is not reachable from ${start}`);
  }

  // Reconstruct path
  const path = [];
  let current = end;

  while (current !== null) {
    path.unshift(current);
    current = previous[current];
  }

  return {
    path: path,
    distance: distances[end]
  };
}

